async function nukeCollection(colPath) {
    const docs = await db.collection(colPath).get();
    let batch = db.batch();
    let count = 0;
    for (const d of docs.docs) {
        batch.delete(d.ref);
        count++;
        if (count >= 400) {
            await batch.commit();
            batch = db.batch();
            count = 0;
        }
    }
    if (count > 0) await batch.commit();
    console.log('??Nuked', colPath);
}

