async function deleteCollection(collectionRef) {
    let count = 0;
    while (true) {
        const snapshot = await collectionRef.limit(100).get();
        if (snapshot.empty) break;
        const batch = db.batch();
        snapshot.docs.forEach((doc) => batch.delete(doc.ref));
        await batch.commit();
        count += snapshot.size;
    }
    return count;
}

