                </div>
            )}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                {matchedClasses.map((cls, idx) => {
                    const colors = getTagColor(cls.title, dateStr, cls.instructor);
                    const isMatched = cls.matchCount > 0;

                    // ?덉빟 ?곹깭 ?뺤씤
                    const myBooking = allowBooking && myBookings.find(b =>
                        b.date === dateStr && b.classIndex === idx && (b.status === 'booked' || b.status === 'waitlisted')
                    );

                    return (
                        <div
                            key={idx}
                            style={{
                                fontSize: '0.8rem',
                                padding: '4px 6px',
                                borderRadius: '6px',
                                backgroundColor: cls.status === 'cancelled' ? 'rgba(255, 71, 87, 0.15)' :
                                    cls.status === 'changed' ? 'rgba(255, 165, 2, 0.15)' : colors.bg,
                                color: cls.status === 'cancelled' ? '#ff6b81' :
                                    cls.status === 'changed' ? '#ffa502' : colors.text,
                                border: myBooking ? '2px solid var(--primary-gold)' : (isMatched ? '2px solid #3498db' : (cls.status === 'cancelled' ? 'none' : `1px solid ${colors.border}`)),
                                textDecoration: cls.status === 'cancelled' ? 'line-through' : 'none',
                                fontWeight: isMatched ? 'bold' : 'normal',
                                boxShadow: myBooking ? '0 0 8px rgba(var(--primary-rgb), 0.4)' : (isMatched ? '0 0 8px rgba(52, 152, 219, 0.5)' : 'none'),
                                position: 'relative',
                                display: 'flex',
                                flexDirection: 'column',
                                gap: '2px',
                                marginBottom: '2px',
                                cursor: (allowBooking && isClassBookable(cls) && cls.status !== 'cancelled') ? 'pointer' : 'default'
                            }}
                            onClick={() => {
                                if (allowBooking && isClassBookable(cls) && cls.status !== 'cancelled') {
                                    onClassClick(dateStr, idx, cls, myBooking);
                                }
                            }}
                        >
                            {/* ?덉빟 ?곹깭 ?꾩씠肄?*/}
                            {myBooking && (
                                <div style={{
                                    position: 'absolute', right: '3px', top: '3px',
                                    fontSize: '0.6rem', fontWeight: 900,
                                    color: myBooking.status === 'waitlisted' ? '#f39c12' : 'var(--primary-gold)',
                                    background: 'rgba(0,0,0,0.5)', borderRadius: '4px', padding: '1px 3px'
                                }}>
                                    {myBooking.status === 'waitlisted' ? '?湲? : '?덉빟'}
                                </div>
                            )}
                            {isMatched && !myBooking && (
                                <div style={{
                                    position: 'absolute', right: '4px', top: '4px',
                                    display: 'flex', alignItems: 'center', gap: '2px'
                                }}>
                                    {cls.matchCount > 1 && (
                                        <span style={{ fontSize: '0.7rem', color: '#3498db', fontWeight: '900' }}>
                                            x{cls.matchCount}
                                        </span>
                                    )}
                                    <div style={{ width: '4px', height: '4px', borderRadius: '50%', background: '#3498db' }} />
                                </div>
                            )}
                            <span style={{ fontWeight: '600', lineHeight: '1.2' }}>{cls.time} {getTranslatedClass(cls.title, t)}</span>
                            {(cls.instructor || cls.level) && (
                                <span style={{ fontSize: '0.85em', opacity: 0.9, lineHeight: '1.2', display: 'block' }}>
                                    {cls.level ? `Lv.${cls.level} ` : ''}{cls.instructor}
                                </span>
                            )}
                        </div>
                    );
                })}

                {/* Autonomous Practice (?먯쑉?섎젴) or Unmatched Attendance */}
                {unmatchedLogs.map((log, idx) => (
                    <div key={`auto-${idx}`} style={{
                        fontSize: '0.75rem',
                        padding: '3px 6px',
                        borderRadius: '6px',
                        backgroundColor: 'rgba(52, 152, 219, 0.1)',
                        color: '#3498db',
                        border: '2px solid #3498db',
                        fontWeight: 'bold',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '4px'
                    }}>
                        <span style={{ fontSize: '0.6rem' }}>??/span>
                        {new Date(log.timestamp).toLocaleTimeString(language === 'ko' ? 'ko-KR' : language, { hour: '2-digit', minute: '2-digit', hour12: false })}
                        {' '}{log.className === '?먯쑉?섎젴' || log.className === '?먯쑉?섏뾽' ? t('auto_practice') : getTranslatedClass(log.className, t)}
                    </div>
                ))}

                {classes.length === 0 && !isAllCancelled && (
                    <span style={{ fontSize: '0.7rem', color: 'rgba(255,255,255,0.2)' }}></span>
                )}
            </div>
        </div>
    );
});

CalendarCell.displayName = 'CalendarCell';

