            </div>

            <AttendanceHistory
                logs={logs}
                member={member}
                aiAnalysis={aiAnalysis}
                language="ko"
                t={(k, params = {}) => {
                    let text = translations.ko[k] || k;
                    Object.keys(params).forEach(p => {
                        text = text.replace(new RegExp(`\\{${p}\\}`, 'g'), params[p]);
                    });
                    return text;
                }}
                onDelete={onDelete}
                isSubmitting={isSubmitting}
                logLimit={logLimit}
                setLogLimit={setLogLimit}
            />
        </div>
    );
};

