    const [sendMode, setSendMode] = useState('push_first');
    const scheduleInputRef = useRef(null);

    if (!isOpen) return null;

    const templates = [
        "[?쇨큵?곗옣] ?대Т濡??명빐 ???뚯썝 ?섍컯 湲곌컙??O???곗옣?섏뿀?듬땲??",
        "[?꾩떆?대Т] O??O??O???대Т ?덈궡?쒕┰?덈떎. ?묓빐 遺?곷뱶由쎈땲???솋",
        "[紐낆젅?몄궗] 利먭굅??紐낆젅 蹂대궡?몄슂! ?고쑕 湲곌컙 ?섍컯沅뚯씠 ?먮룞 ?곗옣?⑸땲??",
        "[?섏뾽蹂寃? ?ㅼ쓬 二??섏뾽 ?쒓컙?쒓? 蹂寃쎈맗?덈떎. ?뺤씤 遺?곷뱶由쎈땲??",
