const handleImageUpload = (e, target, setOptimisticImages) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 5 * 1024 * 1024) {
        alert('?뚯씪 ?⑸웾???덈Т ?쎈땲?? (理쒕? 5MB)');
        return;
    }
    const reader = new FileReader();
    reader.onload = (event) => {
        const img = new Image();
        img.onload = async () => {
            const canvas = document.createElement('canvas');
            const MAX_WIDTH = 900;
            let width = img.width;
            let height = img.height;
            if (width > MAX_WIDTH) { height *= MAX_WIDTH / width; width = MAX_WIDTH; }
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d');
            ctx.drawImage(img, 0, 0, width, height);
            const compressedBase64 = canvas.toDataURL('image/jpeg', 0.5);

            setOptimisticImages(prev => ({ ...prev, [target]: compressedBase64 }));
            try {
                await storageService.updateImage(target, compressedBase64);
            } catch {
                alert("?대?吏 ?낅줈?쒖뿉 ?ㅽ뙣?덉뒿?덈떎.");
            }
        };
        img.src = event.target.result;
    };
    reader.readAsDataURL(file);
};


