import { useState, useEffect, useMemo, useRef } from 'react';
import { X } from '@phosphor-icons/react';
import { storageService } from '../../../services/storage';
import { useStudioConfig } from '../../../contexts/StudioContext';

const MemberAddModal = ({ isOpen, onClose, onSuccess }) => {
    const { config } = useStudioConfig();
    const branches = config.BRANCHES || [];
    const [pricingConfig, setPricingConfig] = useState(config.PRICING || {});
    const [isSubmitting, setIsSubmitting] = useState(false);
    const isSubmittingRef = useRef(false);
    const [dailyClasses, setDailyClasses] = useState([]);

    const [newMember, setNewMember] = useState({
        name: '', phone: '010', branch: branches.length > 0 ? branches[0].id : '',
        membershipType: Object.keys(config.PRICING || {}).find(k => k !== '_meta') || 'general',
        selectedOption: '',
        duration: 1,
        paymentMethod: 'card',
        credits: 0,
        amount: 0,
        regDate: new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }),
        startDate: new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }),
        endDate: '',
        subject: '',
        autoStart: false,
        includeToday: false, // [NEW] Option for "Attended today"
        todayClass: null, // [NEW] To store matched class info
        notes: '' // [NEW] Member notes
    });

    useEffect(() => {
        const loadPricing = async () => {
            const data = await storageService.getPricing();
            if (data) setPricingConfig(data);
        };
        if (isOpen) loadPricing();
    }, [isOpen]);

    // [NEW] ?좏깮 吏?먯쓽 ?ㅻ뒛 ?섏뾽 紐⑸줉 媛?몄삤湲?r
    useEffect(() => {
        const fetchClasses = async () => {
            if (!isOpen || !newMember.branch) return;
            try {
                const today = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
                const classes = await storageService.getDailyClasses(newMember.branch, null, today);
                setDailyClasses(classes || []);
            } catch (err) {
                console.warn('[MemberAddModal] Failed to fetch daily classes:', err);
                setDailyClasses([]);
            }
        };
        fetchClasses();
    }, [isOpen, newMember.branch]);

    // [Smart Calculation Logic for New Member]
    const { calculatedPrice, calculatedCredits, calculatedEndDate, calculatedRealEndDate, calculatedProductName } = useMemo(() => {
        if (!isOpen) return { calculatedPrice: 0, calculatedCredits: 0, calculatedEndDate: '', calculatedRealEndDate: '', calculatedProductName: '' };

        const { membershipType, selectedOption, duration, paymentMethod, startDate, includeToday } = newMember;
        const category = pricingConfig[membershipType];

        if (!category) return { calculatedPrice: 0, calculatedCredits: 0, calculatedEndDate: '', calculatedRealEndDate: '', calculatedProductName: '' };

        const option = category.options.find(opt => opt.id === selectedOption);
        if (!option) return { calculatedPrice: 0, calculatedCredits: 0, calculatedEndDate: '', calculatedRealEndDate: '', calculatedProductName: '' };

        let p = 0;
        let c = 0;
        let months = duration;
        let label = option.label;

        // Price Calculation with Cash/Transfer Price support
        // [FIX] ?댁껜(transfer)???꾧툑怨??숈씪??媛寃??곸슜
        const isCashLike = paymentMethod === 'cash' || paymentMethod === 'transfer';

        if (isCashLike && option.cashPrice !== undefined) {
            p = option.cashPrice;
            // [FIX] Preserve credits for cash payments if option defines it
            c = option.credits === 9999 ? 9999 : option.credits * duration;
            months = duration * (option.months || 1);
        } else {
            if (option.type === 'ticket') {
                p = option.basePrice;
                c = option.credits;
                months = option.months || 3;
            } else {
                c = option.credits === 9999 ? 9999 : option.credits * duration;
                months = duration * (option.months || 1);
                if (duration === 1) p = option.basePrice;
                else if (duration === 3) p = isCashLike && option.cashDiscount3 ? option.cashDiscount3 : (option.discount3 || (option.basePrice * 3));
                else if (duration === 6) p = isCashLike && option.cashDiscount6 ? option.cashDiscount6 : (option.discount6 || (option.basePrice * 6));
                else p = option.basePrice * duration;
            }

            if (isCashLike && duration >= 3 && p > 0 && !option.cashPrice && !option.cashDiscount3 && !option.cashDiscount6) {
                p = Math.round(p * 0.95);
            }
        }

        // [Logic] Deduct 1 credit if today is included
        if (includeToday && c > 0 && c !== 9999) {
            c -= 1;
        }

        const start = new Date(startDate);
        const end = new Date(start);
        end.setMonth(end.getMonth() + months);
        end.setDate(end.getDate() - 1);
        
        const realEnd = end.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });

        return {
            calculatedPrice: p,
            calculatedCredits: c,
            calculatedEndDate: newMember.autoStart ? '泥?異쒖꽍 ???뺤젙' : (newMember.manualEndDate ? newMember.manualEndDate : realEnd),
            calculatedRealEndDate: newMember.manualEndDate ? newMember.manualEndDate : realEnd,
            calculatedProductName: `${label} ${duration > 1 && option.type !== 'ticket' ? `(${duration}媛쒖썡)` : ''}`
        };
    }, [newMember, pricingConfig, isOpen]);

    // Sync newMember state with calculated values
    useEffect(() => {
        if (!isOpen) return;
        setNewMember(prev => ({
            ...prev,
            amount: calculatedPrice,
            credits: calculatedCredits,
            endDate: calculatedEndDate,
            realEndDate: calculatedRealEndDate,
            subject: calculatedProductName,
            manualEndDate: '' // [FIX] ?쒖옉?쇱씠??寃곗젣湲곌컙 蹂寃????섎룞 留덇컧??珥덇린?뷀븯???먮룞怨꾩궛媛??몄텧 蹂댁옣
        }));
    }, [calculatedPrice, calculatedCredits, calculatedEndDate, calculatedRealEndDate, calculatedProductName, isOpen]);

    // pricingConfig/branch/紐⑤떖?대┝ 蹂寃???membershipType怨?selectedOption????긽 ?숈떆 寃利?r
    const getBranchName = (id) => branches.find(b => b.id === id)?.name || id;
    useEffect(() => {
        if (!isOpen) return;
        const validKeys = Object.keys(pricingConfig).filter(k => k !== '_meta');
        if (validKeys.length === 0) return;

        const branchName = getBranchName(newMember.branch);
        const availableTypes = validKeys.filter(key => {
            const cfg = pricingConfig[key];
            return !cfg?.branches || cfg.branches.includes(newMember.branch) || cfg.branches.includes(branchName);
        });
        if (availableTypes.length === 0) return;

        // 1) membershipType 寃利?r
        let targetType = newMember.membershipType;
        if (!availableTypes.includes(targetType)) {
            targetType = availableTypes[0];
        }

        // 2) selectedOption 寃利????꾩옱 ??낆쓽 ?듭뀡 紐⑸줉???ы븿?섏뼱 ?덈뒗吏
        // [FIX] 1?뚭텒(credits === 1 && type === 'ticket') ?쒖쇅
        const options = (pricingConfig[targetType]?.options || []).filter(opt => !(opt.type === 'ticket' && opt.credits === 1));
        const isOptionValid = newMember.selectedOption && options.some(opt => opt.id === newMember.selectedOption);

        const needsTypeChange = targetType !== newMember.membershipType;
        const needsOptionChange = !isOptionValid;

        if (needsTypeChange || needsOptionChange) {
            setNewMember(prev => ({
                ...prev,
                ...(needsTypeChange ? { membershipType: targetType } : {}),
                ...(needsOptionChange ? { selectedOption: options[0]?.id || '' } : {})
            }));
        }
    }, [newMember.branch, newMember.membershipType, newMember.selectedOption, isOpen, pricingConfig]);

    const handleAddMember = async () => {
        if (!newMember.name || !newMember.phone) {
            alert('?대쫫怨??꾪솕踰덊샇???꾩닔?낅땲??');
            return;
        }
        if (isSubmitting) return;

        isSubmittingRef.current = true;
        setIsSubmitting(true);
        try {
            const res = await storageService.addMember({
                name: newMember.name,
                phone: newMember.phone,
                credits: newMember.credits,
                homeBranch: newMember.branch,
                subject: newMember.subject,
                amount: newMember.amount,
                membershipType: newMember.membershipType,
                regDate: newMember.regDate,
                startDate: newMember.autoStart ? 'TBD' : newMember.startDate,
                endDate: newMember.autoStart ? 'TBD' : newMember.endDate,
                duration: newMember.duration,
                attendanceCount: newMember.includeToday ? 1 : 0, // [NEW] Mark initial attendance
                lastAttendance: newMember.includeToday ? new Date().toISOString() : null,
                notes: newMember.notes || ''
            });

            if (newMember.amount > 0) {
                await storageService.addSalesRecord({
                    memberId: res.id,
                    memberName: newMember.name,
                    type: 'register',
                    item: newMember.subject,
                    amount: newMember.amount,
                    paymentMethod: newMember.paymentMethod,
                    date: new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }),
                    branchId: newMember.branch
                });
            }

            // [NEW] Automatically add attendance record if "Include Today" is checked
            if (newMember.includeToday) {
                // [FIX] ISO timestamp ???YYYY-MM-DD ?좎쭨瑜??꾨떖
                // ?댁쟾: new Date().toISOString() ??UTC 蹂?섎릺???쒕쾭?먯꽌 date/classTime???섎せ ??λ맖
                const todayDateStr = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
                await storageService.addManualAttendance(
                    res.id,
                    todayDateStr,
                    newMember.branch,
                    newMember.todayClass?.title || "?깅줉 ?뱀씪 ?섎젴",
                    newMember.todayClass?.instructor || "?쒖뒪???먮룞",
                    { skipCreditDeduction: true } // [FIX] ?대? credits 怨꾩궛 ??1??李④컧?? ?댁쨷 李④컧 諛⑹?
                );
            }

            onSuccess();
            onClose();
