                includeToday: false,
                todayClass: null,
                manualEndDate: '',
                notes: ''
            });
        } catch (err) {
            console.error('Error adding member:', err);
            alert('?뚯썝 ?깅줉 以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎.');
        } finally {
            setIsSubmitting(false);
