            const canonicalInstructor = info?.instructor || log.instructor || '?좎깮??;

            const key = canonicalClassName === '?먯쑉?섎젴'
                ? `${canonicalClassName}-${log.branchId}`
                : `${canonicalClassName}-${canonicalInstructor}-${log.branchId}-${classTime}`;
            
            if (!groups[key]) {
                groups[key] = {
                    className: canonicalClassName,
                    instructor: canonicalClassName === '?먯쑉?섎젴' ? '?뚯썝' : canonicalInstructor,
                    branchId: log.branchId,
                    classTime: canonicalClassName === '?먯쑉?섎젴' ? '' : classTime,
                    count: 0,
                    deniedCount: 0,
                    memberNames: [] 
                };
            }
            if (log.status === 'denied') groups[key].deniedCount++;
