    useEffect(() => {
        setExpandedCards(prev => {
            const next = { ...prev };
            let changed = false;
            if (next.reg === undefined) { next.reg = false; changed = true; }
            if (next.churn === undefined) { next.churn = false; changed = true; }
            if (next.push === undefined) { next.push = false; changed = true; }
            return changed ? next : prev;
