 * videoRef props媛 ?녾굅??srcObject媛 ?놁뼱???먯껜 getUserMedia濡?移대찓?쇰? ?띾뱷?⑸땲??
 */
const FaceRegistrationModal = ({ isOpen, onClose, videoRef: externalVideoRef, modelsAlreadyLoaded = false }) => {
    const [step, setStep] = useState(1); // 1: intro, 2: pin, 3: capture, 4: done
    const [pin, setPin] = useState('');
    const [matchedMember, setMatchedMember] = useState(null);
    const [matchedMembersList, setMatchedMembersList] = useState([]);
    const [countdown, setCountdown] = useState(3);
    const [error, setError] = useState('');
    const [saving, setSaving] = useState(false);
    const [cameraReady, setCameraReady] = useState(false);
    const [cameraError, setCameraError] = useState(false);
    const [statusMsg, setStatusMsg] = useState('');
    const countdownRef = useRef(null);
    const localVideoRef = useRef(null);
    const localStreamRef = useRef(null);

    // Determine which video element to use for face extraction
    const getActiveVideo = useCallback(() => {
        // 1) 紐⑤떖 ?먯껜 鍮꾨뵒?ㅺ? ?쒖꽦?대㈃ ?ъ슜
        if (localVideoRef.current?.srcObject && localVideoRef.current.readyState >= 2) {
            return localVideoRef.current;
        }
        // 2) ?몃? 鍮꾨뵒??ref媛 ?덉쑝硫??ъ슜
        if (externalVideoRef?.current?.srcObject && externalVideoRef.current.readyState >= 2) {
            return externalVideoRef.current;
        }
        return null;
    }, [externalVideoRef]);

    // Reset on open & acquire camera for step 3
    useEffect(() => {
        if (isOpen) {
            setStep(1);
            setPin('');
            setMatchedMember(null);
            setMatchedMembersList([]);
            setCountdown(3);
            setError('');
            setSaving(false);
            setCameraReady(false);
            setCameraError(false);
            setStatusMsg('');
        } else {
            // 紐⑤떖 ?ロ옄 ???먯껜 ?ㅽ듃由??뺣━
            stopLocalCamera();
        }
        return () => {
            if (countdownRef.current) clearInterval(countdownRef.current);
            stopLocalCamera();
        };
    }, [isOpen]);

    const stopLocalCamera = useCallback(() => {
        if (localStreamRef.current) {
            localStreamRef.current.getTracks().forEach(t => t.stop());
            localStreamRef.current = null;
        }
    }, []);

    // step 3 吏꾩엯 ??移대찓??以鍮?n    useEffect(() => {
        if (step === 3) {
            initCamera();
        }
    }, [step]);

    const initCamera = useCallback(async () => {
        setCameraError(false);
        setCameraReady(false);
        setStatusMsg('移대찓??以鍮?以?..');

        // ?몃? 鍮꾨뵒??ref???대? ?ㅽ듃由쇱씠 ?덉쑝硫??ъ슜
        if (externalVideoRef?.current?.srcObject) {
            console.log('[FaceReg] Using external camera stream');
            setCameraReady(true);
            setStatusMsg('');
            return;
        }

        // ?먯껜 移대찓???띾뱷 ?쒕룄
        try {
            console.log('[FaceReg] Acquiring own camera stream');
            const stream = await navigator.mediaDevices.getUserMedia({
                video: { facingMode: 'user', width: 640, height: 480 }
            });
            localStreamRef.current = stream;

            if (localVideoRef.current) {
                localVideoRef.current.srcObject = stream;
                await localVideoRef.current.play().catch(() => {});
            }

            // video媛 ?ㅼ젣 ?꾨젅?꾩쓣 媛?몄삱 ?뚭퉴吏 ?湲?n            await new Promise((resolve) => {
                const checkReady = () => {
                    if (localVideoRef.current?.readyState >= 2) {
                        resolve();
                    } else {
                        setTimeout(checkReady, 100);
                    }
                };
                setTimeout(checkReady, 100);
                // 5珥???꾩븘??n                setTimeout(resolve, 5000);
            });

            setCameraReady(true);
            setStatusMsg('');
            console.log('[FaceReg] Camera ready');
        } catch (err) {
            console.error('[FaceReg] Camera init failed:', err);
            setCameraError(true);
            setCameraReady(false);
            setStatusMsg('');
            setError('移대찓?쇱뿉 ?묎렐?????놁뼱?? 移대찓??沅뚰븳???뺤씤?댁＜?몄슂.');
        }
    }, [externalVideoRef]);

    const handlePinSubmit = useCallback(async () => {
