                        <button onClick={() => { setSaving(false); setStatusMsg(''); setError(''); setCountdown(3); onClose(); }} style={{
                            marginTop: '8px', background: 'none', border: 'none',
                            color: 'rgba(255,255,255,0.4)', fontSize: '0.85rem', cursor: 'pointer'
