                    </div>
                )}

                {/* Step 4: ?꾨즺 */}
                {step === 4 && (
                    <div style={{ animation: 'slideUp 0.4s ease-out' }}>
                        <div style={{ fontSize: '3.5rem', marginBottom: '12px' }}>??/div>
