                            boxShadow: 'inset 0 0 20px rgba(0,0,0,0.2)'
                        }}>
                            "{aiExperience.subMessage}"
                        </div>
                    )}

                    {/* [SUCCESS DETAILS] Grid for credits and days remaining */}
                    {message.type === 'success' && (
                        <SuccessDetails 
                            member={message.member} 
                            onClose={onClose} 
                        />
                    )}
                    
                    {message.type !== 'success' && (
