            {/* 以??뚰듃 */}
            <div style={{
                position: 'absolute',
                bottom: '30px',
                left: '50%',
                transform: 'translateX(-50%)',
                color: 'rgba(255, 255, 255, 0.5)',
                fontSize: '0.8rem',
                textAlign: 'center',
                pointerEvents: 'none'
            }}>
                {scale > 1 ? '?쒕옒洹명븯???대룞' : '???먭??쎌쑝濡??뺣? ???붾툝 ??쑝濡?以?}
            </div>

            {/* ?대?吏 */}
            <img
                src={src}
                alt="?뺣? 蹂닿린"
                onClick={handleDoubleTap}
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
