                            </div>
                        ) : (
                            (config.BRANCHES || []).map(branch => (
                                renderAttendanceList(
                                    attendanceByBranch[branch.id] || [], 
                                    (config.BRANCHES?.length > 1 ? branch.name : '異쒖꽍 ?꾪솴'), 
                                    branch.color, 
                                    branch.id
