import { useState, useEffect } from 'react';
import { storageService } from '../../services/storage';
import { ClockCounterClockwise } from '@phosphor-icons/react';
import { useStudioConfig } from '../../contexts/StudioContext';
import { getMembershipLabel } from '../../utils/membershipLabels';
import { useLanguage } from '../../hooks/useLanguage';


const MemberSalesHistory = ({ memberId, member }) => {
    const { t } = useLanguage();
    const { config } = useStudioConfig();
    const [history, setHistory] = useState([]);
    const [loading, setLoading] = useState(true);

    const fetchHistory = async () => {
        try {
            setLoading(true);
            const data = await storageService.getSalesHistory(memberId);
            const sorted = [...data].sort((a, b) => {
                const timeA = new Date(a.timestamp || a.date).getTime();
                const timeB = new Date(b.timestamp || b.date).getTime();
                return timeB - timeA;
            });
            setHistory(sorted);
        } catch (e) {
            console.error('Failed to fetch sales history:', e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (memberId) {
            fetchHistory();
        }
    }, [memberId]);

    // Derived active membership info
    const todayStr = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
    const isPending = member && member.startDate && member.startDate > todayStr;
    const isActive = !isPending && member && member.endDate && new Date(member.endDate) >= new Date();
    const isExpired = !isPending && member && member.endDate && new Date(member.endDate) < new Date();

    if (loading) {
        return (
            <div style={{ textAlign: 'center', padding: '20px', color: 'rgba(255,255,255,0.5)' }}>
                <p>{t('loadingPayment')}</p>
            </div>
        );
    }

    return (
        <div style={{ marginBottom: '20px' }}>
            {/* 1. Current/Upcoming Membership Status */}
            {member && (
                <div style={{ marginBottom: '20px' }}>
                    <h4 style={{ color: 'rgba(255,255,255,0.8)', fontSize: '1rem', marginBottom: '12px', fontWeight: 'bold', marginLeft: '4px' }}>{t('myPassStatus')}</h4>
                    <div style={{
                        background: 'linear-gradient(135deg, rgba(var(--primary-rgb), 0.1) 0%, rgba(255,255,255,0.02) 100%)',
                        padding: '16px',
                        borderRadius: '20px',
                        border: '1px solid rgba(var(--primary-rgb), 0.3)',
                        boxShadow: '0 4px 16px rgba(0, 0, 0, 0.2)'
                    }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '14px' }}>
                            <div style={{ display: 'flex', flexDirection: 'column' }}>
                                <span style={{ color: 'var(--primary-gold)', fontWeight: 'bold', fontSize: '1.15rem' }}>
                                    {(() => {
                                        // Find matching sales record for current membership period
                                        const matchingSale = history.find(h => h.startDate === member.startDate && h.endDate === member.endDate);
                                        if (matchingSale && matchingSale.item) {
                                            return `${getMembershipLabel(matchingSale.item.split(' ')[0], config)} ${matchingSale.item.split(' ').slice(1).join(' ')}`;
                                        }
                                        return getMembershipLabel(member.membershipType, config);
                                    })()}
                                </span>
                            </div>
                            <span style={{
                                color: isPending ? '#38bdf8' : (isActive ? '#10b981' : (isExpired ? '#ef4444' : '#a1a1aa')),
                                fontWeight: 'bold',
                                fontSize: '0.85rem',
                                padding: '4px 10px',
                                background: isPending ? 'rgba(56,189,248,0.1)' : (isActive ? 'rgba(16,185,129,0.1)' : (isExpired ? 'rgba(239,68,68,0.1)' : 'rgba(255,255,255,0.05)')),
                                borderRadius: '12px',
                                border: `1px solid ${isPending ? 'rgba(56,189,248,0.3)' : (isActive ? 'rgba(16,185,129,0.2)' : (isExpired ? 'rgba(239,68,68,0.2)' : 'rgba(255,255,255,0.1)'))}`
                            }}>
                                {isPending ? t('statusPending') : (isActive ? t('statusActive') : (isExpired ? t('statusExpired') : t('statusNone')))}
                            </span>
                        </div>

                        <div style={{
                            display: 'grid',
                            gridTemplateColumns: '1fr 1fr 1fr',
                            gap: '10px',
                            fontSize: '0.9rem',
                            color: '#e4e4e7',
                            marginBottom: '6px',
                            background: 'rgba(0,0,0,0.3)',
                            padding: '12px',
                            borderRadius: '12px'
                        }}>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                                <span style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.5)' }}>{t('startDate')}</span>
                                <span style={{ fontWeight: '600', color: 'rgba(255,255,255,0.9)' }}>{member.startDate || '-'}</span>
                            </div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', textAlign: 'center' }}>
                                <span style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.5)' }}>{t('endDate')}</span>
                                <span style={{ fontWeight: '600', color: 'rgba(255,255,255,0.9)' }}>{member.endDate || '-'}</span>
                            </div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', textAlign: 'right' }}>
                                <span style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.5)' }}>{t('remainCount')}</span>
                                <span style={{ fontWeight: '600', color: 'var(--primary-gold)' }}>
                                    {member.credits >= 9000 ? t('unlimited') : `${member.credits}${t('countUnit')}`}
                                </span>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            <h4 style={{ color: 'rgba(255,255,255,0.8)', fontSize: '1rem', marginBottom: '12px', fontWeight: 'bold', marginLeft: '4px' }}>{t('paymentHistory')}</h4>

            {history.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '30px 20px', color: 'rgba(255,255,255,0.5)', background: 'rgba(255,255,255,0.02)', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)' }}>
                    <ClockCounterClockwise size={32} style={{ marginBottom: '10px', opacity: 0.5 }} />
                    <p style={{ margin: 0, fontSize: '0.9rem' }}>{t('noPaymentHistory')}</p>
                </div>
            ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                    {history.map((item) => {
                        const itemStart = item.startDate ? new Date(`${item.startDate}T00:00:00+09:00`).getTime() : null;
                        const itemEnd = item.endDate ? new Date(`${item.endDate}T23:59:59+09:00`).getTime() : null;
                        const now = new Date().getTime();
                        let isItemActive = false;
                        let isItemUpcoming = false;

                        if (itemStart && itemEnd) {
                            if (now >= itemStart && now <= itemEnd) {
                                isItemActive = true;
                            } else if (now < itemStart) {
                                isItemUpcoming = true;
                            }
                        }

                        return (
                            <div key={item.id} style={{
                                background: 'rgba(255,255,255,0.04)',
                                padding: '16px',
                                borderRadius: '16px',
                                border: isItemActive ? '1px solid rgba(var(--primary-rgb), 0.4)' : (isItemUpcoming ? '1px solid rgba(56, 189, 248, 0.4)' : '1px solid rgba(255,255,255,0.08)'),
                                transition: 'all 0.2s ease',
                                boxShadow: '0 4px 12px rgba(0,0,0,0.1)'
                            }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px', alignItems: 'center' }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
                                        <span style={{ color: 'white', fontWeight: 'bold', fontSize: '1rem' }}>
                                            {item.item ? `${getMembershipLabel(item.item.split(' ')[0], config)} ${item.item.split(' ').slice(1).join(' ')}` : t('paymentItem')}
                                        </span>
                                        {isItemActive && <span style={{ fontSize: '0.7rem', background: 'rgba(var(--primary-rgb), 0.15)', color: 'var(--primary-gold)', border: '1px solid rgba(var(--primary-rgb), 0.3)', padding: '2px 6px', borderRadius: '6px', fontWeight: 'bold' }}>{t('currentlyUsing')}</span>}
                                        {isItemUpcoming && <span style={{ fontSize: '0.7rem', background: 'rgba(56, 189, 248, 0.15)', color: '#38bdf8', border: '1px solid rgba(56, 189, 248, 0.3)', padding: '2px 6px', borderRadius: '6px', fontWeight: 'bold' }}>{t('preRegistered')}</span>}
                                    </div>
                                    <span style={{ color: '#10b981', fontWeight: 'bold', fontSize: '1.05rem' }}>{(item.amount || 0).toLocaleString()}{t('won')}</span>
                                </div>

                                {/* 湲곌컙 ?쒖떆 */}
                                {item.startDate && item.endDate && (
                                    <div style={{ fontSize: '0.85rem', color: 'rgba(255,255,255,0.6)', marginBottom: '8px', display: 'flex', alignItems: 'center', gap: '6px' }}>
                                        <span style={{ opacity: 0.8 }}>?뱟</span> {item.startDate} ~ {item.endDate}
                                    </div>
                                )}

                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', fontSize: '0.8rem' }}>
                                    <span style={{ color: 'rgba(255,255,255,0.4)', background: 'rgba(255,255,255,0.05)', padding: '2px 8px', borderRadius: '4px' }}>
                                        {item.paymentMethod === 'card' ? t('payCard') : item.paymentMethod === 'cash' ? t('payCash') : item.paymentMethod === 'none' ? t('payOther') : t('payTransfer')}
                                    </span>
                                    <span style={{ color: 'rgba(255,255,255,0.4)' }}>
                                        {new Date(item.timestamp || item.date).toLocaleDateString('ko-KR', { timeZone: 'Asia/Seoul' })} {t('paidOn')}
                                    </span>
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

export default MemberSalesHistory;

import React, { useState } from 'react';
import { useStudioConfig } from '../../contexts/StudioContext';
import { getMembershipLabel } from '../../utils/membershipLabels';
import { toKSTDateString } from '../../utils/dates';
import { Icons } from '../CommonIcons';
import { functions } from '../../firebase';
import { httpsCallable } from 'firebase/functions';

const MembershipInfo = ({ member, daysRemaining, logs = [], t }) => {
    const { config } = useStudioConfig();
    const [showHoldModal, setShowHoldModal] = useState(false);
    const [holdDays, setHoldDays] = useState(7);
    const [holdLoading, setHoldLoading] = useState(false);

    const allowSelfHold = config.POLICIES?.ALLOW_SELF_HOLD || false;
    let holdRules = config.POLICIES?.HOLD_RULES || [];

    // [?듭뀡B] duration??紐낆떆?곸쑝濡??덈뒗 ?뚯썝留????媛??r
    const memberDuration = member.duration || 0;

    // duration???놁쑝硫????遺덇?
    let matchedRule = null;
    if (memberDuration > 0 && holdRules.length > 0) {
        // ?뺥솗??留ㅼ묶 ???놁쑝硫??묎굅??媛숈? 寃?以?理쒕?
        matchedRule = holdRules.find(r => r.durationMonths === memberDuration);
        if (!matchedRule) {
            const eligible = holdRules.filter(r => r.durationMonths <= memberDuration).sort((a, b) => b.durationMonths - a.durationMonths);
            matchedRule = eligible[0] || null;
        }
    }

    const isHolding = member.holdStatus === 'holding';
    const holdHistory = member.holdHistory || [];
    const usedHoldCount = holdHistory.filter(h => !h.cancelledAt).length;
    const canHold = allowSelfHold && matchedRule && !isHolding && usedHoldCount < (matchedRule.maxCount || 1);




    const handleApplyHold = async () => {
        if (!member.id || holdDays <= 0) return;
        setHoldLoading(true);
        try {
            const applyHold = httpsCallable(functions, 'applyMemberHoldCall');
            const result = await applyHold({ memberId: member.id, holdDays });
            if (result.data.success) {
                alert(result.data.message || t('holdApplied'));
                setShowHoldModal(false);
                window.location.reload(); // ?곹깭 ?덈줈怨좎묠
            } else {
                alert(result.data.message || t('holdFailed'));
            }
        } catch (e) {
            console.error('Hold apply failed:', e);
            alert(e.message || t('holdError'));
        } finally {
            setHoldLoading(false);
        }
    };

    // ???以묒씪 ???덉긽 醫낅즺??怨꾩궛
    const getHoldEndInfo = () => {
        if (!isHolding || !member.holdStartDate) return null;
        const start = new Date(member.holdStartDate);
        const today = new Date();
        const elapsed = Math.max(1, Math.round((today - start) / (1000 * 60 * 60 * 24)));
        const requested = member.holdRequestedDays || 14;
        return { elapsed, requested, startDate: member.holdStartDate };
    };

    const holdInfo = getHoldEndInfo();

    return (
        <div style={{ padding: '0 0 20px 0' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '15px', flexWrap: 'wrap' }}>
                <h1 style={{ fontSize: '1.8rem', fontWeight: 'bold', margin: 0, color: 'white' }}>{member.displayName || member.name} {t('nim')}</h1>
                <span style={{ background: 'var(--primary-gold)', color: 'var(--text-on-primary)', padding: '3px 10px', borderRadius: '5px', fontSize: '0.75rem', fontWeight: 'bold' }}>
                    {(config.BRANCHES || []).find(b => b.id === member.homeBranch)?.name || member.homeBranch}
                </span>
                {member.hasFaceDescriptor && (
                    <span style={{ 
                        background: 'rgba(99, 102, 241, 0.15)', 
                        color: '#818CF8', 
                        padding: '3px 10px', 
                        borderRadius: '5px', 
                        fontSize: '0.75rem', 
                        fontWeight: 'bold',
                        border: '1px solid rgba(99, 102, 241, 0.3)',
                        display: 'flex', alignItems: 'center', gap: '4px'
                    }}>
                        ?뮔 AI 異쒖꽍 ?깅줉
                    </span>
                )}
                {isHolding && (
                    <span style={{ 
                        background: 'rgba(251, 146, 60, 0.2)', 
                        color: '#fb923c', 
                        padding: '3px 10px', 
                        borderRadius: '5px', 
                        fontSize: '0.75rem', 
                        fontWeight: 'bold',
                        border: '1px solid rgba(251, 146, 60, 0.3)',
                        animation: 'pulse 2s infinite'
                    }}>
                        {t('holdingStatus')}
                    </span>
                )}
                <span style={{ background: 'rgba(255,255,255,0.1)', color: 'white', padding: '3px 10px', borderRadius: '5px', fontSize: '0.75rem' }}>{member.phone}</span>
                {typeof window !== 'undefined' && window.location.hostname.includes('passflow') ? null : (
                    <img src={config.ASSETS?.LOGO?.RYS200} alt="RYS200" style={{ height: '49px', width: 'auto', marginLeft: 'auto', filter: 'brightness(0) invert(1)' }} />
                )}
            </div>
            {/* [NEW] ?덈㈃?몄떇 ?덉떖 臾멸뎄 */}
            {member.hasFaceDescriptor && (
                <div style={{ 
                    marginBottom: '12px',
                    padding: '10px 14px', 
                    background: 'rgba(99, 102, 241, 0.06)', 
                    borderRadius: '10px',
                    border: '1px solid rgba(99, 102, 241, 0.15)',
                    display: 'flex', alignItems: 'flex-start', gap: '10px'
                }}>
                    <span style={{ fontSize: '1.1rem', flexShrink: 0 }}>?뵏</span>
                    <div style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.6)', lineHeight: '1.5' }}>
                        <span style={{ color: '#818CF8', fontWeight: 'bold' }}>AI 異쒖꽍 ?덈궡</span> ??
                        ?뚯썝?섏쓽 ?ъ쭊? <b style={{ color: 'rgba(255,255,255,0.85)' }}>??λ릺吏 ?딆뒿?덈떎.</b> ?쇨뎬 ?뱀쭠??128李⑥썝 ?レ옄(踰≫꽣)濡?蹂?섎릺???덉쟾?섍쾶 蹂닿??섎ŉ, ?먮낯 ?대?吏??利됱떆 ??젣?⑸땲?? ?レ옄 ?곗씠?곕줈???쇨뎬??蹂듭썝?????놁뒿?덈떎.
                    </div>
                </div>
            )}

            {/* ???以묒씪 ???곹깭 ?쒖떆 */}
            {isHolding && holdInfo && (
                <div style={{ 
                    padding: '16px 20px', 
                    background: 'linear-gradient(135deg, rgba(251, 146, 60, 0.1), rgba(251, 146, 60, 0.05))', 
                    borderRadius: '16px', 
                    border: '1px solid rgba(251, 146, 60, 0.2)', 
                    marginBottom: '16px' 
                }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <div>
