                                        overflow: 'hidden',
                                        boxShadow: isSelected ? '0 0 30px rgba(var(--primary-rgb), 0.3)' : '0 15px 35px rgba(0,0,0,0.3)',
                                        transition: 'all 0.3s ease'
                                    }}>
                                    {((notice.images && notice.images.length > 0) || notice.image || notice.imageUrl) ? (
                                        <div>
                                            {/* Header (Title & Date) - Now above image */}
                                            <div style={{ padding: '24px 24px 15px' }}>
                                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '15px' }}>
                                                    <h3 style={{ fontSize: '1.4rem', fontWeight: '900', color: 'var(--primary-gold)', margin: 0, lineHeight: '1.3', wordBreak: 'keep-all', userSelect: 'text', WebkitUserSelect: 'text' }}>
                                                        {notice.title}
                                                    </h3>
                                                    <span style={{
                                                        fontSize: '0.7rem',
                                                        color: 'rgba(255,255,255,0.7)',
                                                        whiteSpace: 'nowrap',
                                                        background: 'rgba(255, 255, 255, 0.1)',
                                                        padding: '4px 12px',
                                                        borderRadius: '20px',
                                                        fontWeight: '600',
                                                        border: '1px solid rgba(255,255,255,0.05)'
                                                    }}>
                                                        {notice.date || (notice.createdAt ? new Date(notice.createdAt).toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }) : t('recent'))}
                                                    </span>
                                                </div>
                                            </div>

                                            {/* Image - Now below title */}
                                            <div style={{
                                                display: 'flex',
                                                overflowX: 'auto',
                                                overflowY: 'hidden',
                                                scrollSnapType: 'x mandatory',
                                                gap: '0',
                                                width: '100%',
                                                WebkitOverflowScrolling: 'touch'
                                            }}>
                                                {notice.images && notice.images.length > 0 ? (
                                                    notice.images.map((img, idx) => (
                                                        <div key={idx} style={{
                                                            minWidth: '100%',
                                                            scrollSnapAlign: 'start',
                                                            position: 'relative'
                                                        }}>
                                                            <img
                                                                src={img}
                                                                alt="notice"
                                                                style={{
                                                                    width: '100%',
                                                                    height: 'auto',
                                                                    maxHeight: '500px',
                                                                    objectFit: 'contain',
                                                                    display: 'block',
                                                                    borderTop: '1px solid rgba(255,255,255,0.05)',
                                                                    borderBottom: '1px solid rgba(255,255,255,0.05)',
                                                                    cursor: 'pointer',
                                                                    backgroundColor: 'rgba(0,0,0,0.2)'
                                                                }}
                                                                onClick={() => setLightboxImage(img)}
                                                            />
                                                            {notice.images.length > 1 && (
                                                                <div style={{
                                                                    position: 'absolute',
                                                                    bottom: '10px',
                                                                    right: '10px',
                                                                    background: 'rgba(0,0,0,0.6)',
                                                                    padding: '4px 8px',
                                                                    borderRadius: '12px',
                                                                    color: 'white',
                                                                    fontSize: '0.75rem',
                                                                    fontWeight: 'bold'
                                                                }}>
                                                                    {idx + 1} / {notice.images.length}
                                                                </div>
                                                            )}
                                                        </div>
                                                    ))
                                                ) : (
                                                    <img
                                                        src={notice.image || notice.imageUrl}
                                                        alt="notice"
                                                        style={{
                                                            width: '100%',
                                                            height: 'auto',
                                                            display: 'block',
                                                            borderTop: '1px solid rgba(255,255,255,0.05)',
                                                            borderBottom: '1px solid rgba(255,255,255,0.05)',
                                                            cursor: 'pointer'
                                                        }}
                                                        onClick={() => setLightboxImage(notice.image || notice.imageUrl)}
                                                    />
                                                )}
                                            </div>
                                        </div>
                                    ) : (
                                        <div style={{ padding: '24px 24px 10px' }}>
                                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '12px', gap: '10px' }}>
                                                <h3 style={{ fontSize: '1.25rem', fontWeight: '800', color: 'var(--primary-gold)', margin: 0, lineHeight: '1.4', wordBreak: 'keep-all' }}>
                                                    {notice.title}
                                                </h3>
                                                <span style={{
                                                    fontSize: '0.75rem',
                                                    color: 'rgba(255,255,255,0.5)',
                                                    whiteSpace: 'nowrap',
                                                    background: 'rgba(var(--primary-rgb), 0.15)',
                                                    padding: '4px 12px',
                                                    borderRadius: '20px',
                                                    fontWeight: '600'
                                                }}>
                                                    {notice.date || (notice.createdAt ? new Date(notice.createdAt).toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }) : t('recent'))}
                                                </span>
                                            </div>
                                        </div>
                                    )}

                                    <div style={{ padding: '20px 24px 30px' }}>
                                        <p style={{
                                            margin: 0,
                                            fontSize: '1.05rem',
                                            color: 'rgba(255,255,255,0.9)',
                                            lineHeight: '1.8',
                                            whiteSpace: 'pre-wrap',
                                            wordBreak: 'break-all',
                                            userSelect: 'text',
                                            WebkitUserSelect: 'text'
                                        }}>
                                            {notice.content}
                                        </p>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <div className="glass-panel" style={{ padding: '40px 20px', textAlign: 'center', background: 'rgba(255,255,255,0.02)' }}>
                        <Icons.Megaphone size={40} style={{ opacity: 0.2, marginBottom: '15px' }} />
                        <p style={{ color: 'rgba(255,255,255,0.4)', margin: 0, textAlign: 'center' }}>{t('noNewNotices')}</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default NoticeTab;

import React, { useState, useEffect } from 'react';
import MemberSalesHistory from '../MemberSalesHistory';
import { storageService } from '../../../services/storage';
import { useLanguage } from '../../../hooks/useLanguage';
import { useStudioConfig } from '../../../contexts/StudioContext';

const PriceTab = ({
    memberId,
    member,
    images,
    priceTable1,
    priceTable2,
    setLightboxImage
}) => {
    const { t } = useLanguage();
    const { config } = useStudioConfig();
    const [pricing, setPricing] = useState(null);
    const [activeCategory, setActiveCategory] = useState(null);

    useEffect(() => {
        const loadPricing = async () => {
            const data = await storageService.getPricing();
            setPricing(data);
            const keys = Object.keys(data).filter(k => k !== '_meta');
            // ?쇰컲(general)??湲곕낯 ?좏깮
            if (keys.includes('general')) setActiveCategory('general');
            else if (keys.length > 0) setActiveCategory(keys[0]);
        };
        loadPricing();
    }, []);

    const paymentInfo = pricing?._meta?.payment || null;
    const holdRules = pricing?._meta?.holdRules || null;
    const discountNote = pricing?._meta?.discountNote || null;

    // 移댄뀒怨좊━ ?쒖꽌: ?쇰컲?곸씤 寃?癒쇱?, ?뱀닔??寃??ㅻ줈
    const CATEGORY_ORDER = ['general', 'advanced'];
    const categories = pricing
        ? Object.entries(pricing)
            .filter(([k]) => k !== '_meta')
            .sort(([a], [b]) => {
                const aIdx = CATEGORY_ORDER.indexOf(a);
                const bIdx = CATEGORY_ORDER.indexOf(b);
                if (aIdx !== -1 && bIdx !== -1) return aIdx - bIdx;
                if (aIdx !== -1) return -1;
                if (bIdx !== -1) return 1;
                return a.localeCompare(b);
            })
        : [];

    return (
        <div className="fade-in">
            {/* ?뚯썝 寃곗젣 ?댁뿭 */}
            {member && memberId && (
                <MemberSalesHistory memberId={memberId} member={member} />
            )}

            {/* 媛寃⑺몴 ?뚯씠釉?酉?*/}
            {pricing && categories.length > 0 && (
                <div style={{ marginBottom: '24px' }}>
                    {/* 移댄뀒怨좊━ ??*/}
                    <div style={{
                        display: 'flex', gap: '8px', overflowX: 'auto',
                        paddingBottom: '12px', marginBottom: '16px',
                        borderBottom: '1px solid rgba(255,255,255,0.08)'
                    }}>
                        {categories.map(([key, cat]) => (
                            <button
                                key={key}
                                onClick={() => setActiveCategory(key)}
                                style={{
                                    padding: '8px 18px',
                                    borderRadius: '20px',
                                    border: activeCategory === key ? '1px solid var(--primary-gold)' : '1px solid rgba(255,255,255,0.12)',
                                    background: activeCategory === key ? 'rgba(var(--primary-rgb), 0.15)' : 'rgba(255,255,255,0.04)',
                                    color: activeCategory === key ? 'var(--primary-gold)' : 'var(--text-secondary)',
                                    fontWeight: activeCategory === key ? '700' : '500',
                                    fontSize: '0.85rem',
                                    cursor: 'pointer',
                                    whiteSpace: 'nowrap',
                                    transition: 'all 0.2s'
                                }}
                            >
                                {cat.label || key}
                            </button>
                        ))}
                    </div>

                    {/* ?좏깮??移댄뀒怨좊━ 媛寃⑺몴 */}
                    {activeCategory && pricing[activeCategory] && (
                        <div style={{ animation: 'fadeIn 0.3s ease' }}>
                            {/* 湲곕낯 ?④???*/}
                            <div style={{
                                background: 'rgba(255,255,255,0.03)',
                                borderRadius: '14px',
                                border: '1px solid rgba(255,255,255,0.08)',
                                overflow: 'hidden',
                                marginBottom: '16px'
                            }}>
                                <div style={{
                                    padding: '14px 16px',
                                    background: 'rgba(var(--primary-rgb), 0.08)',
                                    borderBottom: '1px solid rgba(255,255,255,0.06)',
                                    display: 'flex', justifyContent: 'space-between', alignItems: 'center'
                                }}>
                                    <span style={{ fontWeight: '700', color: 'var(--primary-gold)', fontSize: '0.95rem' }}>
                                        {pricing[activeCategory].label} {t('tuitionFee')}
                                    </span>
                                    {pricing[activeCategory].branches && (
                                        <div style={{ display: 'flex', gap: '4px' }}>
                                            {pricing[activeCategory].branches.map(b => (
                                                <span key={b} style={{
                                                    fontSize: '0.7rem', padding: '2px 8px',
                                                    background: 'rgba(255,255,255,0.08)', borderRadius: '10px',
                                                    color: 'var(--text-tertiary)'
                                                }}>{config.BRANCHES?.find(branch => branch.id === b)?.name || b}</span>
                                            ))}
                                        </div>
                                    )}
                                </div>

                                {pricing[activeCategory].options?.map((opt, idx) => (
                                    <div
                                        key={idx}
                                        style={{
                                            display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                                            padding: '14px 16px',
                                            borderBottom: idx < pricing[activeCategory].options.length - 1 ? '1px solid rgba(255,255,255,0.04)' : 'none',
                                            transition: 'background 0.2s'
                                        }}
                                    >
                                        <div>
                                            <div style={{ fontWeight: '600', fontSize: '0.9rem', color: 'var(--text-primary)' }}>
                                                {opt.label}
                                            </div>
                                            <div style={{ fontSize: '0.72rem', color: 'var(--text-tertiary)', marginTop: '2px' }}>
                                                {opt.credits === 9999 ? t('unlimited') : `${opt.credits}${t('countUnit')}`}
                                                {opt.months > 1 ? ` 쨌 ${opt.months}${t('monthUnit')}` : ''}
                                                {opt.type === 'ticket' ? ` 쨌 ${t('ticketType')}` : ''}
                                            </div>
                                        </div>
                                        <div style={{ textAlign: 'right' }}>
                                            <div style={{ fontWeight: '700', fontSize: '1rem', color: 'var(--text-primary)' }}>
                                                {opt.basePrice?.toLocaleString()}{t('won')}
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>

                            {/* ?κ린?깅줉 ?좎씤 ?뚯씠釉?*/}
                            {pricing[activeCategory].options?.some(opt => opt.discount3 || opt.discount6) && (
                                <div style={{
                                    background: 'rgba(16,185,129,0.04)',
                                    borderRadius: '14px',
                                    border: '1px solid rgba(16,185,129,0.12)',
                                    overflow: 'hidden',
                                    marginBottom: '16px'
                                }}>
                                    <div style={{
                                        padding: '12px 16px',
                                        background: 'rgba(16,185,129,0.08)',
                                        borderBottom: '1px solid rgba(16,185,129,0.1)',
                                        fontWeight: '700', color: '#10B981', fontSize: '0.9rem'
                                    }}>
                                        {t('longTermDiscount')}
                                    </div>

                                    {/* ?뚯씠釉??ㅻ뜑 */}
                                    <div style={{
                                        display: 'grid', gridTemplateColumns: '1fr 1fr 1fr',
                                        padding: '10px 16px', gap: '8px',
                                        borderBottom: '1px solid rgba(255,255,255,0.04)',
                                        fontSize: '0.72rem', color: 'var(--text-tertiary)', fontWeight: '600'
                                    }}>
                                        <span>{t('classLabel')}</span>
                                        <span style={{ textAlign: 'right' }}>{t('threeMonthDiscount')}</span>
                                        <span style={{ textAlign: 'right' }}>{t('sixMonthDiscount')}</span>
                                    </div>

                                    {pricing[activeCategory].options
                                        .filter(opt => opt.discount3 || opt.discount6)
                                        .map((opt, idx, arr) => (
                                            <div key={idx} style={{
                                                display: 'grid', gridTemplateColumns: '1fr 1fr 1fr',
                                                padding: '12px 16px', gap: '8px',
                                                borderBottom: idx < arr.length - 1 ? '1px solid rgba(255,255,255,0.04)' : 'none'
                                            }}>
                                                <span style={{ fontWeight: '600', fontSize: '0.85rem' }}>{opt.label}</span>
                                                <div style={{ textAlign: 'right' }}>
                                                    {opt.discount3 && (
                                                        <>
                                                            <div style={{ fontWeight: '700', fontSize: '0.85rem', color: '#10B981' }}>
                                                                {opt.discount3.toLocaleString()}{t('won')}
                                                            </div>
                                                            {opt.cashDiscount3 && (
                                                                <div style={{ fontSize: '0.68rem', color: '#f59e0b' }}>
                                                                    {t('cashLabel')} {opt.cashDiscount3.toLocaleString()}{t('won')}
                                                                </div>
                                                            )}
                                                        </>
                                                    )}
                                                </div>
                                                <div style={{ textAlign: 'right' }}>
                                                    {opt.discount6 && (
                                                        <>
                                                            <div style={{ fontWeight: '700', fontSize: '0.85rem', color: '#10B981' }}>
                                                                {opt.discount6.toLocaleString()}{t('won')}
                                                            </div>
                                                            {opt.cashDiscount6 && (
                                                                <div style={{ fontSize: '0.68rem', color: '#f59e0b' }}>
                                                                    {t('cashLabel')} {opt.cashDiscount6.toLocaleString()}{t('won')}
                                                                </div>
                                                            )}
                                                        </>
                                                    )}
                                                </div>
                                            </div>
                                        ))
                                    }
                                </div>
                            )}
                        </div>
                    )}

                    {/* ?덈궡?ы빆 + 寃곗젣怨꾩쥖 */}
                    <div style={{
                        background: 'rgba(255,255,255,0.03)',
                        borderRadius: '14px',
                        border: '1px solid rgba(255,255,255,0.08)',
                        padding: '16px',
                        marginBottom: '16px'
                    }}>
                        {discountNote && (
                            <div style={{
                                fontSize: '0.82rem', color: '#f59e0b', fontWeight: '600',
                                marginBottom: '12px', lineHeight: '1.5'
                            }}>
                                狩?{discountNote}
                            </div>
                        )}

                        {holdRules && (
                            <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginBottom: '12px', lineHeight: '1.6' }}>
                                ?뱥 <strong>{t('deferRules')}</strong><br/>
                                {holdRules.map((rule, i) => (
                                    <span key={i}>??{rule}<br/></span>
                                ))}
                            </div>
                        )}

                        {paymentInfo && (
                            <div style={{
                                background: 'rgba(var(--primary-rgb), 0.06)',
                                borderRadius: '10px',
                                border: '1px solid rgba(var(--primary-rgb), 0.12)',
                                padding: '14px',
                                display: 'flex', flexDirection: 'column', gap: '6px'
                            }}>
                                <div style={{ fontWeight: '700', color: 'var(--primary-gold)', fontSize: '0.9rem', marginBottom: '4px' }}>
                                    {t('paymentAccount')}
                                </div>
                                <div style={{ fontSize: '0.85rem', color: 'var(--text-primary)' }}>
                                    <strong>{paymentInfo.bank}</strong> {paymentInfo.account}
                                </div>
                                <div style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>
                                    {t('accountHolder')}: {paymentInfo.holder}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* 湲곗〈 媛寃⑺몴 ?대?吏 */}
            {(images.price_table_1 || priceTable1) && (
                <img
                    src={images.price_table_1 || priceTable1}
                    style={{ width: '100%', borderRadius: '15px', marginBottom: '15px', cursor: 'pointer' }}
                    alt="price"
                    onClick={() => setLightboxImage(images.price_table_1 || priceTable1)}
                />
            )}
            {(images.price_table_2 || priceTable2) && (
                <img
                    src={images.price_table_2 || priceTable2}
                    style={{ width: '100%', borderRadius: '15px', cursor: 'pointer' }}
                    alt="price"
                    onClick={() => setLightboxImage(images.price_table_2 || priceTable2)}
                />
            )}
        </div>
    );
};

export default PriceTab;

import React from 'react';
import * as Icons from '@phosphor-icons/react';
import MemberScheduleCalendar from '../../MemberScheduleCalendar';
import { useStudioConfig } from '../../../contexts/StudioContext';

const ScheduleTab = ({
    t,
    scheduleView,
    setScheduleView,
    scheduleBranch,
    setScheduleBranch,
    validLogs,
    scheduleMonth,
    setScheduleMonth,
    images,
    timeTable1,
    timeTable2,
    setLightboxImage,
    member
}) => {
    const { config } = useStudioConfig();
    const viewToggleStyle = {
        border: 'none',
        padding: '6px 16px',
        fontSize: '0.85rem',
        fontWeight: 'bold',
        cursor: 'pointer',
        transition: 'all 0.3s ease',
        whiteSpace: 'nowrap'
    };

    return (
        <div className="fade-in">
            <div className="glass-panel" style={{ padding: '24px', background: 'rgba(15, 15, 15, 0.9)', minHeight: '400px', border: '1px solid rgba(var(--primary-rgb), 0.2)' }}>
                <div style={{ marginBottom: '25px', textAlign: 'left' }}>
                    <h2 style={{ fontSize: '1.5rem', color: 'white', fontWeight: '800', margin: '0 0 8px 0', letterSpacing: '-0.02em' }}>{t('scheduleTitle')}</h2>
                    <p style={{ margin: 0, fontSize: '0.95rem', color: config.THEME?.PRIMARY_COLOR || 'var(--primary-gold)', opacity: 0.9, lineHeight: '1.5', whiteSpace: 'pre-wrap' }}>
                        {t('scheduleSub')}
                    </p>
                </div>

                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                    <div style={{ background: 'rgba(255,255,255,0.05)', padding: '4px', borderRadius: '12px', display: 'flex', gap: '4px' }}>
                        <button onClick={() => setScheduleView('calendar')} style={{ ...viewToggleStyle, background: scheduleView === 'calendar' ? 'white' : 'transparent', color: scheduleView === 'calendar' ? 'black' : 'white', borderRadius: '8px' }}>{t('viewCalendar')}</button>
                        <button onClick={() => setScheduleView('image')} style={{ ...viewToggleStyle, background: scheduleView === 'image' ? 'white' : 'transparent', color: scheduleView === 'image' ? 'black' : 'white', borderRadius: '8px' }}>{t('viewWeekly')}</button>
                    </div>
                </div>

                <div style={{ display: 'flex', gap: '10px', marginBottom: '25px' }}>
                    {(config.BRANCHES || []).map((b, i) => {
                        const isSelected = scheduleBranch === b.id || (!scheduleBranch && i === 0);
                        return (
                            <button
                                key={b.id}
                                onClick={() => setScheduleBranch(b.id)}
                                style={{
                                    flex: 1,
                                    padding: '12px',
                                    borderRadius: '12px',
                                    fontWeight: 'bold',
                                    border: isSelected ? 'none' : '1px solid rgba(255,255,255,0.1)',
                                    background: isSelected ? 'var(--primary-gold)' : 'rgba(255,255,255,0.03)',
                                    color: isSelected ? 'black' : 'rgba(255,255,255,0.6)',
                                    fontSize: '0.9rem',
                                    transition: 'all 0.3s ease',
                                    boxShadow: isSelected ? '0 4px 15px rgba(var(--primary-rgb), 0.3)' : 'none'
                                }}
                            >
                                {b.name}
                            </button>
                        );
                    })}
                </div>
                {scheduleView === 'calendar' ? (
                    <MemberScheduleCalendar branchId={scheduleBranch || config.BRANCHES?.[0]?.id} attendanceLogs={validLogs} memberId={member?.id} memberName={member?.name} />
                ) : (
                    (() => {
                        const now = new Date();
                        const currentYear = now.getFullYear();
                        const currentMonthStr = String(now.getMonth() + 1).padStart(2, '0');
                        const currentKeyDate = `${currentYear}-${currentMonthStr}`;

                        const nextDate = new Date(now.getFullYear(), now.getMonth() + 1, 1);
                        const nextYear = nextDate.getFullYear();
                        const nextMonthStr = String(nextDate.getMonth() + 1).padStart(2, '0');
                        const nextKeyDate = `${nextYear}-${nextMonthStr}`;

                        const currentBranchId = scheduleBranch || config.BRANCHES?.[0]?.id;

                        const currentKey = `timetable_${currentBranchId}_${currentKeyDate}`;
                        const nextKey = `timetable_${currentBranchId}_${nextKeyDate}`;
                        const oldKey = `timetable_${currentBranchId}`;

                        const hasNext = !!images[nextKey];
                        const activeMonth = scheduleMonth === 'next' && hasNext ? 'next' : 'current';
                        const displayImage = activeMonth === 'next' ? images[nextKey] : (images[currentKey] || images[oldKey] || timeTable1);

                        return (
                            <div style={{ position: 'relative', width: '100%', borderRadius: '10px', overflow: 'hidden' }}>
                                {/* Month Navigation Overlay */}
                                <div style={{
                                    display: 'flex',
                                    justifyContent: 'space-between',
                                    alignItems: 'center',
                                    marginBottom: '10px',
                                    padding: '0 5px'
                                }}>
