import { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import { getDoc, doc, setDoc, onSnapshot } from 'firebase/firestore';
import { db } from '../firebase';
import { useStudioConfig } from '../contexts/StudioContext';
import { PWAContext } from './PWAContextDef';

export const PWAProvider = ({ children }) => {
    const { config } = useStudioConfig();
    const location = useLocation();

    const [deferredPrompt, setDeferredPrompt] = useState(null);
    const [deviceOS, setDeviceOS] = useState('unknown');
    const [isStandalone, setIsStandalone] = useState(false);

    const isDemo = typeof window !== 'undefined' && (
        window.location.hostname.includes('passflowai') || 
        window.location.hostname.includes('demo') || 
        config?.STUDIO_ID === 'demo' || 
        config?.STUDIO_ID === 'demo-yoga'
    );

    useEffect(() => {
        // OS 媛먯?
        const ua = navigator.userAgent.toLowerCase();
        if (/iphone|ipad|ipod/.test(ua)) setDeviceOS('ios');
        else if (/android/.test(ua)) setDeviceOS('android');
        
        // PWA ?ㅼ튂 ?곹깭 媛먯?
        const checkStandalone = () => {
            const isInstalled = window.matchMedia('(display-mode: standalone)').matches || window.navigator.standalone === true;
            setIsStandalone(isInstalled);
        };
        checkStandalone();
        const handleBeforeInstallPrompt = (e) => {
            e.preventDefault();
            // ?곕え ?섍꼍?먯꽌???ㅼ튂 ?꾨＼?꾪듃瑜??몄텧?섏? ?딆쓬
            if (isDemo) {
                return;
            }
            setDeferredPrompt(e);
        };

        window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

        // Check if already installed
        window.addEventListener('appinstalled', () => {
            setDeferredPrompt(null);
            setIsStandalone(true);
        });

        return () => {
            window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
        };
    }, []);

    // Handle dynamic manifest and title
    useEffect(() => {
        const path = location.pathname.toLowerCase(); // [FIX] ??뚮Ц??臾댁떆
        let manifestFile = '/manifest-checkin.json';
        const studioName = config?.IDENTITY?.NAME || "Studio";
        let appTitle = `${studioName} 異쒖꽍泥댄겕`;

        if (path.startsWith('/admin')) {
            manifestFile = '/manifest-admin.json';
            appTitle = `${studioName} 愿由ъ옄`;
        } else if (path.startsWith('/member')) {
            manifestFile = '/manifest-member.json';
            appTitle = '?댁슂媛'; // This title is specific and not using studioName
        } else if (path.startsWith('/instructor')) {
            manifestFile = '/manifest-instructor.json';
            appTitle = `${studioName} ?좎깮??;
        } else if (path === '/login') {
            appTitle = `${studioName} 濡쒓렇??;
        } else if (path === '/meditation') {
            appTitle = `${studioName} 紐낆긽`;
        }

        // Update manifest link
        let link = document.querySelector('link[rel="manifest"]');
        if (!link) {
            link = document.createElement('link');
            link.rel = 'manifest';
            document.head.appendChild(link);
        }
        link.href = manifestFile;

        // Update title and meta
        document.title = appTitle;

        let appleTitle = document.querySelector('meta[name="apple-mobile-web-app-title"]');
        if (!appleTitle) {
            appleTitle = document.createElement('meta');
            appleTitle.name = 'apple-mobile-web-app-title';
            document.head.appendChild(appleTitle);
        }
        appleTitle.content = appTitle;


    }, [location]);

    const installApp = async () => {
        if (!deferredPrompt) {

            return false;
        }

        try {
            deferredPrompt.prompt();
            const { outcome } = await deferredPrompt.userChoice;


            if (outcome === 'accepted') {
                setDeferredPrompt(null);
                return true;
            }
            return false;
        } catch (error) {
            console.error('[PWA] Prompt execution failed:', error);
            return false;
        }
    };

    return (
        <PWAContext.Provider value={{ deferredPrompt, installApp, isStandalone, deviceOS, isDemo }}>
            {children}
        </PWAContext.Provider>
    );
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { db, auth } from '../firebase';
import { useStudioStore } from '../stores/useStudioStore';
import { doc, onSnapshot, setDoc, getDoc } from 'firebase/firestore';
import { onAuthStateChanged, signInAnonymously } from 'firebase/auth';
import { STUDIO_CONFIG as STATIC_CONFIG } from '../studioConfig';
import { resolveStudioId, onStudioChange, getCurrentStudioId } from '../utils/resolveStudioId';

const StudioContext = createContext();

export const useStudioConfig = () => {
    const context = useContext(StudioContext);
    if (!context) {
        throw new Error('useStudioConfig must be used within a StudioProvider');
    }
    return context;
};

export const StudioProvider = ({ children }) => {
    const [config, setConfig] = useState(STATIC_CONFIG);
    const [loading, setLoading] = useState(true);
    const [studioId, setStudioId] = useState(() => resolveStudioId());

    // [MULTI-STUDIO] ?몃??먯꽌 switchStudio() ?몄텧 ??studioId 蹂寃?媛먯?
    useEffect(() => {
        const unsub = onStudioChange((newId) => {
            setLoading(true);
            setStudioId(newId);
        });
        return unsub;
    }, []);

    useEffect(() => {
        const studioDocRef = doc(db, 'studios', studioId);

        let unsubscribeSnapshot = null;

        const unsubscribeAuth = onAuthStateChanged(auth, async (user) => {
            if (!user) {
                try {
                    await signInAnonymously(auth);
                } catch (e) {
                    console.warn('[?ㅽ뒠?붿삤] ?듬챸 ?몄쬆 ?ㅽ뙣, 湲곕낯 ?ㅼ젙?쇰줈 吏꾪뻾:', e);
                    setLoading(false);
                    return;
                }
                return;
            }

            // [AUTO-SEEDING]
            try {
                const snap = await getDoc(studioDocRef);
                if (!snap.exists()) {
                    await setDoc(studioDocRef, STATIC_CONFIG);
                }
            } catch (e) {
                console.error('[?ㅽ뒠?붿삤] 珥덇린 ?ㅼ젙 ????ㅽ뙣:', e);
            }

        // [REAL-TIME SYNC]
        unsubscribeSnapshot = onSnapshot(studioDocRef, (snap) => {
            if (snap.exists()) {
                const cloudConfig = snap.data();
                
                // [DEEP-MERGE] Combine Static and Cloud to prevent missing keys
                const merged = JSON.parse(JSON.stringify(STATIC_CONFIG));
                const deepMerge = (target, source) => {
                    for (const key in source) {
                        // [TRUTHY ONLY] Ignore empty strings, nulls, or undefined from cloud
                        const val = source[key];
                        if (val === "" || val === null || val === undefined) continue;

                        if (typeof val === 'object' && !Array.isArray(val)) {
                            if (!target[key]) target[key] = {};
                            deepMerge(target[key], val);
                        } else {
                            target[key] = val;
                        }
                    }
                };
                deepMerge(merged, cloudConfig);

                // [SELF-HEALING] Enhanced Path Correction
                if (merged.ASSETS) {
                    const fixPaths = (obj) => {
                        for (const key in obj) {
                            if (typeof obj[key] === 'string' && (key === 'WIDE' || key === 'SQUARE' || key === 'RYS200' || key === 'MEMBER_BG' || obj[key].endsWith('.webp'))) {
                                let path = obj[key];
                                // Remove duplicate/missing slash issues
                                if (path.includes('assets/') && !path.startsWith('/assets/')) {
                                    path = path.substring(path.indexOf('assets/'));
                                }
                                if (!path.startsWith('/') && !path.startsWith('http')) {
                                    path = `/${path}`;
                                }
                                obj[key] = path;
                            } else if (typeof obj[key] === 'object' && obj[key] !== null) {
                                fixPaths(obj[key]);
                            }
                        }
                    };
                    fixPaths(merged.ASSETS);

                    // [SaaS] 以묐┰??湲곕낯 濡쒓퀬 ???뚮꼳?멸? ?먯껜 濡쒓퀬 ?깅줉 ?꾧퉴吏 ?쒖떆
                    if (!merged.ASSETS.LOGO?.WIDE || merged.ASSETS.LOGO.WIDE === '/') merged.ASSETS.LOGO.WIDE = '/assets/passflow_logo.png';
                    if (!merged.ASSETS.LOGO?.RYS200 || merged.ASSETS.LOGO.RYS200 === '/') merged.ASSETS.LOGO.RYS200 = '/assets/RYS200.webp';
                    if (!merged.ASSETS.LOGO?.SQUARE || merged.ASSETS.LOGO.SQUARE === '/') merged.ASSETS.LOGO.SQUARE = '/assets/passflow_logo.png';
                }

                // [DEMO OVERRIDE] ?먯옣???붿껌: ?곕え ?ъ씠?몃뒗 臾댁“嫄?PassFlow 濡쒓퀬 ?몄텧
                if (window.location.hostname.includes('passflow') || window.location.hostname.includes('demo') || studioId === 'demo-yoga') {
                    if (!merged.ASSETS) merged.ASSETS = {};
                    if (!merged.ASSETS.LOGO) merged.ASSETS.LOGO = {};
                    merged.ASSETS.LOGO.WIDE = '/assets/passflow_ai_logo_transparent_final.png';
                    merged.ASSETS.LOGO.SQUARE = '/assets/passflow_ai_logo_transparent_final.png';
                    if (!merged.IDENTITY) merged.IDENTITY = {};
                    merged.IDENTITY.NAME = 'PassFlow Ai ?곕え ?뚮옯??;
                    merged.IDENTITY.LOGO_URL = '/assets/passflow_ai_logo_transparent_final.png';
                }

                setConfig(merged);
                useStudioStore.getState().setConfig(merged);

                // Update CSS Variables dynamically
                const theme = merged.THEME || {};
                const primary = theme.PRIMARY_COLOR || 'var(--primary-gold)';
                document.documentElement.style.setProperty('--primary-theme-color', primary);
                document.documentElement.style.setProperty('--primary-theme-skeleton', theme.SKELETON_COLOR || 'rgba(var(--primary-rgb), 0.1)');
            }
            setLoading(false);
                useStudioStore.getState().setLoading(false);
        }, (error) => {
            console.error('[?ㅽ뒠?붿삤] ?ㅼ젙 ?숆린???ㅻ쪟:', error);
            setLoading(false);
                useStudioStore.getState().setLoading(false);
        });
        }); // end onAuthStateChanged

        return () => {
            unsubscribeAuth();
            if (unsubscribeSnapshot) unsubscribeSnapshot();
        };
    }, [studioId]);

    const updateConfig = async (newConfig) => {
        try {
            const studioId = resolveStudioId();
            const studioDocRef = doc(db, 'studios', studioId);
            await setDoc(studioDocRef, newConfig, { merge: true });
            return true;
        } catch (e) {
            console.error('[?ㅽ뒠?붿삤] ?ㅼ젙 ?낅뜲?댄듃 ?ㅽ뙣:', e);
            throw e;
        }
    };

    const value = {
        config,
        loading,
        updateConfig,
        // Helper to get nested values safely with fallback
        get: (path, fallback) => {
            return path.split('.').reduce((obj, key) => (obj && obj[key] !== undefined) ? obj[key] : undefined, config) || fallback;
        }
    };

    return (
        <StudioContext.Provider value={value}>
            {!loading && children}
            {loading && (
                <div style={{
                    height: '100vh', 
                    display: 'flex', 
                    alignItems: 'center', 
                    justifyContent: 'center',
                    background: '#08080A',
                    color: 'var(--primary-gold)'
                }}>
                    <div className="pulse">?ㅽ뒠?붿삤 以鍮?以?..</div>
                </div>
            )}
        </StudioContext.Provider>
    );
};

