            const result = await storageService.addManualAttendance(member.id, combinedDateStr, branchId, className || '?섎룞 ?뺤씤', instructorName || '愿由ъ옄');
            if (result.success) {
                if (member.startDate === 'TBD') {
                    const startDateStr = dateStr;
                    const d = new Date(dateStr);
                    const end = new Date(d); end.setMonth(end.getMonth() + (member.duration || 1)); end.setDate(end.getDate() - 1);
                    const endDateStr = end.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
                    await storageService.updateMember(member.id, { startDate: startDateStr, endDate: endDateStr });
                    setLocalMember(prev => ({ ...prev, startDate: startDateStr, endDate: endDateStr }));
                    if (onUpdateMember) onUpdateMember(member.id, { startDate: startDateStr, endDate: endDateStr });
                }
                if (member.upcomingMembership) {
                    try {
                        const fresh = await storageService.getMemberById(member.id);
                        if (fresh) setLocalMember(prev => ({ ...prev, credits: fresh.credits, startDate: fresh.startDate, endDate: fresh.endDate, membershipType: fresh.membershipType, upcomingMembership: fresh.upcomingMembership || null }));
                    } catch {}
                }
                alert('?섎룞 異쒖꽍泥섎━媛 ?꾨즺?섏뿀?듬땲??');
            } else {
                alert('異쒖꽍 泥섎━???ㅽ뙣?덉뒿?덈떎: ' + (result.message || '?????녿뒗 ?ㅻ쪟'));
            }
        } catch (e) {
            console.error(e);
            alert('異쒖꽍 泥섎━???ㅽ뙣?덉뒿?덈떎.');
        } finally {
            isSubmittingRef.current = false;
            setIsSubmitting(false);
        }
    }, [isSubmitting, member]);

    // ??? Delete Attendance ???
    const handleDeleteAttendance = useCallback(async (logId) => {
        if (isSubmitting) return;
        if (!confirm('?뺣쭚 ??젣?섏떆寃좎뒿?덇퉴?')) return;
        isSubmittingRef.current = true;
        setIsSubmitting(true);
        try {
            const result = await storageService.deleteAttendance(logId, true);
            if (result.success) {
                setTimeout(() => { storageService.notifyListeners('logs'); storageService.notifyListeners('members'); }, 500);
            } else {
                throw new Error(result.message || '??젣 ?ㅽ뙣');
            }
        } catch (e) {
            console.error(e);
            alert(`??젣???ㅽ뙣?덉뒿?덈떎: ${e.message}`);
        } finally {
            isSubmittingRef.current = false;
            setIsSubmitting(false);
        }
    }, [isSubmitting]);

    return {
        member, editData, memberLogs, logLimit, setLogLimit,
        isSubmitting, aiAnalysis, isDirtyByUser,
        activeTab, setActiveTab,
        showChangeModal, setShowChangeModal, pendingChanges, selectedChangeKeys, setSelectedChangeKeys,
        setEditData: (updater) => { setIsDirtyByUser(true); setEditData(updater); },
        setEditDataRaw: setEditData,
        handlePreSave, handleFinalSave, handleSafeClose,
        handleManualAttendance, handleDeleteAttendance,
        FIELD_LABELS,
    };
};

// src/hooks/useAttendanceCamera.js
import { useEffect, useRef, useCallback, useState } from 'react';
import { storage } from '../firebase';
import { ref as storageRef, uploadBytes, getDownloadURL } from 'firebase/storage';
import { tenantStoragePath } from '../utils/tenantStorage';
import { storageService } from '../services/storage';

export const useAttendanceCamera = (PHOTO_ENABLED) => {
    const videoRef = useRef(null);
    const canvasRef = useRef(null);
    const cameraStreamRef = useRef(null);
    const capturedPhotoRef = useRef(null);
    const isCapturingRef = useRef(false);
    const lastCaptureTimeRef = useRef(0);
    const capturePromisesRef = useRef([]);
    const isRecoveringRef = useRef(false);
    const recoveryCountRef = useRef(0);
    const [stream, setStream] = useState(null);

    // [PHOTO] 移대찓??珥덇린??(?ъ궗??媛?ν븳 ?⑥닔濡?遺꾨━)
    const initCamera = useCallback(async (reason = 'initial') => {
        if (!PHOTO_ENABLED) return false;
        if (isRecoveringRef.current) {
            console.log('[PHOTO] Recovery already in progress, skipping.');
            return false;
        }

        isRecoveringRef.current = true;

        try {
            // 湲곗〈 ?ㅽ듃由??뺣━
            if (cameraStreamRef.current) {
                try {
                    cameraStreamRef.current.getTracks().forEach(t => t.stop());
                } catch (e) {}
                cameraStreamRef.current = null;
            }

            const streamObj = await navigator.mediaDevices.getUserMedia({
                video: { facingMode: 'user', width: { ideal: 800 }, height: { ideal: 600 } }
            });

            cameraStreamRef.current = streamObj;
            setStream(streamObj);

            // [FIX] track.onended ?대깽??媛먯떆 ???ㅽ듃由쇱씠 二쎌쑝硫??먮룞 蹂듦뎄
            streamObj.getVideoTracks().forEach(track => {
                track.onended = () => {
                    console.warn(`[PHOTO] ?좑툘 Camera track ended unexpectedly! Reason: ${track.label}`);
                    cameraStreamRef.current = null;
                    setStream(null);
                    // 吏㏃? ?쒕젅?????먮룞 蹂듦뎄 ?쒕룄
                    setTimeout(() => initCamera('track_ended'), 2000);
                };
            });

            if (videoRef.current) {
                videoRef.current.srcObject = streamObj;
                videoRef.current.setAttribute('autoplay', '');
                videoRef.current.setAttribute('muted', '');
                videoRef.current.setAttribute('playsinline', '');

                await videoRef.current.play().catch(e => {
                    console.warn('[PHOTO] Autoplay blocked, will retry on interaction:', e);
                });
            }

            recoveryCountRef.current = reason === 'initial' ? 0 : recoveryCountRef.current + 1;
            console.log(`[PHOTO] Camera initialized successfully (${reason}). Recovery count: ${recoveryCountRef.current}`);
            return true;
        } catch (err) {
            console.error(`[PHOTO] ??Camera init failed (${reason}):`, err.message);
            return false;
        } finally {
            isRecoveringRef.current = false;
        }
    }, [PHOTO_ENABLED]);

    // [PHOTO] ?ㅽ듃由??곹깭 ?뺤씤 ?좏떥由ы떚
    const isStreamAlive = useCallback(() => {
        if (!cameraStreamRef.current) return false;
        const tracks = cameraStreamRef.current.getVideoTracks();
        if (tracks.length === 0) return false;
        // track.readyState: 'live' = ?뺤긽, 'ended' = 二쎌쓬
        return tracks.some(t => t.readyState === 'live');
    }, []);

    // [PHOTO] 移대찓??珥덇린??+ 蹂듦뎄 援щ룆
    useEffect(() => {
        if (!PHOTO_ENABLED) return;

        let isMounted = true;

        // 珥덇린 移대찓???ㅼ젙
        initCamera('initial');

        // [FIX] visibilitychange 湲곕컲 移대찓??蹂듦뎄
        // ?쒕툝由우씠 ?덉쟾?먯꽌 源⑥뼱?섎㈃ 移대찓???ㅽ듃由쇱씠 二쎌뼱?덉쓣 ???덉쓬
        const handleVisibilityChange = () => {
            if (document.visibilityState === 'visible' && isMounted) {
                // ?좎떆 ?湲????ㅽ듃由??곹깭 ?뺤씤 (OS媛 由ъ냼?ㅻ? ?ы븷?뱁븷 ?쒓컙)
                setTimeout(() => {
                    if (!isMounted) return;
                    if (!isStreamAlive()) {
                        console.warn('[PHOTO] ?좑툘 Camera stream dead after visibility change. Recovering...');
                        initCamera('visibility_recovery');
                    } else {
                        // ?ㅽ듃由쇱? ?댁븘?덉?留?video媛 paused?????덉쓬
                        if (videoRef.current && videoRef.current.paused) {
                            console.log('[PHOTO] Video paused after visibility change, resuming...');
                            videoRef.current.play().catch(() => {});
                        }
                    }
                }, 1000);
            }
        };
        document.addEventListener('visibilitychange', handleVisibilityChange);

        // [FIX] 3遺?Heartbeat ???ㅽ듃由?嫄닿컯 泥댄겕
        const heartbeatInterval = setInterval(() => {
            if (!isMounted || document.visibilityState !== 'visible') return;

            if (!isStreamAlive()) {
                console.warn('[PHOTO] ?좑툘 Heartbeat: Camera stream is dead. Recovering...');
                initCamera('heartbeat_recovery');
            } else if (videoRef.current && videoRef.current.paused) {
                console.log('[PHOTO] Heartbeat: Video is paused, resuming...');
                videoRef.current.play().catch(() => {});
            }
        }, 3 * 60 * 1000); // 3遺?n
        return () => {
            isMounted = false;
            document.removeEventListener('visibilitychange', handleVisibilityChange);
            clearInterval(heartbeatInterval);
            if (cameraStreamRef.current) {
                cameraStreamRef.current.getTracks().forEach(t => t.stop());
                cameraStreamRef.current = null;
                setStream(null);
            }
            if (videoRef.current) videoRef.current.srcObject = null;
        };
    }, [PHOTO_ENABLED, initCamera, isStreamAlive]);

    // [PHOTO] ?꾨젅??罹≪쿂 ??Silent Return 濡쒓퉭 媛뺥솕
    const capturePhoto = useCallback(() => {
        if (!PHOTO_ENABLED) {
            // L63 silent return ???댁젣 濡쒓렇 異붽?
            return;
        }

        // [O] Cooldown: Don't capture more than once every 10 seconds to save CPU
        const now = Date.now();
        if (now - lastCaptureTimeRef.current < 10000 && capturedPhotoRef.current) {
            console.log('[PHOTO] Skipping capture: cooling down');
            return;
        }

        // [FIX] Silent return 寃쎈줈??濡쒓렇 異붽? + ?ㅽ듃由?蹂듦뎄 ?몃━嫄?n        if (!videoRef.current || !canvasRef.current) {
            console.warn('[PHOTO] ?좑툘 Missing video/canvas ref. Cannot capture.');
            return;
        }

        if (!cameraStreamRef.current || !isStreamAlive()) {
            console.warn('[PHOTO] ?좑툘 Camera stream is not available. Triggering recovery + retry...');
            initCamera('capture_recovery').then(ok => {
                if (ok) {
                    // [SaaS FIX] 蹂듦뎄 ?깃났 ??1.5珥????ъ벙泥?(移대찓???덉젙???湲?
                    setTimeout(() => {
                        const v = videoRef.current;
                        if (v && v.readyState >= 2 && !v.paused && isStreamAlive()) {
                            console.log('[PHOTO] ??Recovery succeeded, retrying capture...');
                            doCapture(v);
                        } else {
                            console.warn('[PHOTO] ?좑툘 Recovery succeeded but video still not ready.');
                        }
                    }, 1500);
                }
            });
            return;
        }

        const video = videoRef.current;
        if (video.readyState < 2 || video.paused) {
            console.warn(`[PHOTO] ?좑툘 Video not ready (readyState=${video.readyState}, paused=${video.paused}). Attempting play + delayed retry...`);
            video.play().catch(() => {});
            // [FIX] 利됱떆 ?ш린?섏? 留먭퀬 500ms ???쒕쾲 ???쒕룄
            setTimeout(() => {
                if (video.readyState >= 2 && !video.paused) {
                    console.log('[PHOTO] Retry after play() succeeded. Capturing now...');
                    doCapture(video);
                } else {
                    console.warn('[PHOTO] ?좑툘 Retry failed. Video still not ready.');
                }
            }, 500);
            return;
        }

        doCapture(video);
    }, [PHOTO_ENABLED, initCamera, isStreamAlive]);

    // ?ㅼ젣 罹≪쿂 濡쒖쭅 遺꾨━
    const doCapture = useCallback((video) => {
        const canvas = canvasRef.current;
        if (!canvas) return;

        // [CRITICAL FIX] Clear old photo so uploadPhoto is forced to wait for THIS new capture
        capturedPhotoRef.current = null;

        // [O] Set higher resolution (800x600)
        canvas.width = 800;
        canvas.height = 600;

        const ctx = canvas.getContext('2d');
        ctx.drawImage(video, 0, 0, 800, 600);

        isCapturingRef.current = true;
        const capturePromise = new Promise((resolve) => {
            const timeout = setTimeout(() => {
                console.warn('[PHOTO] ?좑툘 toBlob timed out after 5s');
                isCapturingRef.current = false;
                resolve(null);
            }, 5000);

            try {
                // [O] Switch to WebP for better compression (v10)
                canvas.toBlob((blob) => {
                    clearTimeout(timeout);
                    if (blob) {
                        capturedPhotoRef.current = blob;
                        lastCaptureTimeRef.current = Date.now();
                        console.log(`[PHOTO] ??Captured WebP: ${(blob.size / 1024).toFixed(1)}KB`);
                    } else {
                        console.warn('[PHOTO] ?좑툘 toBlob returned null blob');
                    }
                    isCapturingRef.current = false;
                    resolve(blob);
                }, 'image/webp', 0.8);
            } catch (err) {
                clearTimeout(timeout);
                console.error('[PHOTO] ??toBlob threw:', err.message);
                isCapturingRef.current = false;
                resolve(null);
            }
        });

        capturePromisesRef.current.push(capturePromise);
        if (capturePromisesRef.current.length > 3) capturePromisesRef.current.shift();
    }, []);

    // [PHOTO] 鍮꾨룞湲??낅줈??n    const uploadPhoto = async (attendanceId, memberName, status) => {
        if (!PHOTO_ENABLED) return;
        // [FIX] navigator.onLine 泥댄겕 ?쒓굅 ???쒕툝由우뿉???섎せ 媛먯??????덉쓬
        // ?낅줈???쒕룄 ???ㅽ뙣?섎㈃ catch?먯꽌 泥섎━

        // [CRITICAL FIX] Always wait if capture is active, regardless of having an old blob
        if (isCapturingRef.current && capturePromisesRef.current.length > 0) {
            console.log('[PHOTO] Waiting for active capture...');
            const lastPromise = capturePromisesRef.current[capturePromisesRef.current.length - 1];
            await Promise.race([
                lastPromise,
                new Promise(r => setTimeout(r, 6000))
            ]);
        }

        // [FIX] blob???꾩쭅 ?놁쑝硫?吏㏃? ?湲????ы솗??(toBlob 肄쒕갚 吏???鍮?
        if (!capturedPhotoRef.current) {
            console.log('[PHOTO] No blob yet, waiting 500ms...');
            await new Promise(r => setTimeout(r, 500));
        }

        const blob = capturedPhotoRef.current;
        if (!blob) {
            console.warn(`[PHOTO] ??No captured photo for upload. Stream alive: ${isStreamAlive()}. Member: ${memberName || 'unknown'}`);
            // [FIX] ?ъ쭊 ?낅줈???ㅽ뙣瑜??먮윭 濡쒓렇??湲곕줉
            try {
                storageService.logError(`[PHOTO] No photo available at upload time`, { 
                    memberName: memberName || 'unknown',
                    attendanceId,
                    streamAlive: isStreamAlive(),
                    hasVideo: !!videoRef.current,
                    videoReadyState: videoRef.current?.readyState,
                    videoPaused: videoRef.current?.paused,
                    timeSinceLastCapture: Date.now() - lastCaptureTimeRef.current
                });
            } catch (e) {}
            return;
        }

        if (!attendanceId) {
            console.warn('[PHOTO] No attendanceId provided (offline mode?). Skipping doc update.');
        }

        try {
            const today = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
            const fileName = `${attendanceId || Date.now()}.webp`;
            const path = tenantStoragePath(`attendance-photos/${today}/${fileName}`);
            const fileRef = storageRef(storage, path);

            await uploadBytes(fileRef, blob, { contentType: 'image/webp' });
            const url = await getDownloadURL(fileRef);

            if (attendanceId) {
                const { updateDoc } = await import('firebase/firestore');
                const { tenantDb } = await import('../utils/tenantDb');
                await updateDoc(tenantDb.doc('attendance', attendanceId), {
                    photoUrl: url,
                    photoStatus: status || 'unknown'
                });
            }
            console.log(`[PHOTO] ??Upload Success: ${path} (${(blob.size / 1024).toFixed(1)}KB)`);
        } catch (err) {
            console.error(`[PHOTO] ??Upload failed:`, err.message);
            try {
                storageService.logError(`[PHOTO] Upload failed for ${memberName || 'unknown'}`, { 
                    error: err.message, 
                    attendanceId 
                });
            } catch (e) {}
        } finally {
            // [O] Immediate memory release
            capturedPhotoRef.current = null;
        }
    };

    return {
        videoRef,
        canvasRef,
        capturePhoto,
        uploadPhoto,
        stream
    };
};

import { useEffect, useRef, useCallback, useState } from 'react';
import { extractFaceDescriptor, findBestMatch, loadFacialModels, euclideanDistance } from '../services/facialService';

/**
 * useFacialRecognition ???쇨뎬 ?몄떇 愿??濡쒖쭅 ??n * CheckInPage?먯꽌 異붿텧. 紐⑤뜽 濡쒕뱶, ?앹껜 罹먯떆, ?ㅼ떆媛??ㅼ틪??愿由?
 * 
 * [洹쇰낯 ?섏젙 v2] 2026.03.29
 * 1. ?꾧퀎媛?0.5 ??0.42 (?곗씠??遺꾩꽍 寃곌낵 0.42~0.50 援ш컙?먯꽌 ?섎갚 ?띿쓽 ?ㅼ씤??諛쒖깮)
 * 2. 2nd-best gap 寃利?異붽?: best match? 2nd best??嫄곕━ 李⑥씠媛 0.08 ?댁긽???뚮쭔 ?먮룞 異쒖꽍
 * 3. 異쒖꽍 ??移대찓???ㅽ듃由?怨듭쑀: attendanceVideoRef瑜?諛쏆븘???ъ쭊 罹≪쿂???ъ슜
 * 4. ?몄떇 ??15珥?荑⑤떎??+ isIdle 蹂듦? ?뺤씤
 */
export function useFacialRecognition({ enabled, autoUpdateRef, proceedWithCheckIn, attendanceVideoRef }) {
    const [faceModelsLoaded, setFaceModelsLoaded] = useState(false);
    const [isScanning, setIsScanning] = useState(false);
    const faceVideoRef = useRef(null);
    const biometricsCache = useRef([]);
    const scanIntervalRef = useRef(null);
    const lastAutoCheckInRef = useRef(0);
    const lastDescriptorRef = useRef(null);
    const activeTaskIdRef = useRef(0);

    // 紐⑤뜽 濡쒕뱶 ??enabled=true???뚮쭔 (?덈㈃?몄떇 OFF硫?紐⑤뜽 ?먯껜瑜?濡쒕뱶?섏? ?딆쓬)
    useEffect(() => {
        if (!enabled) return;
        loadFacialModels().then(() => setFaceModelsLoaded(true));
    }, [enabled]);

    // ?앹껜 罹먯떆 ?꾨━濡쒕뱶
    useEffect(() => {
        if (!enabled || !faceModelsLoaded) return;

        const loadBiometrics = async () => {
            try {
                const { getDocs } = await import('firebase/firestore');
                const { tenantDb } = await import('../utils/tenantDb');
                const snap = await getDocs(tenantDb.collection('face_biometrics'));
                biometricsCache.current = snap.docs.map(d => ({ memberId: d.id, ...d.data() }));
                console.log(`[FACIAL] Biometrics loaded: ${biometricsCache.current.length} members`);
            } catch (e) {
                console.warn('[FACIAL] Biometrics cache load failed:', e);
            }
        };
        loadBiometrics();
        const refreshInterval = setInterval(loadBiometrics, 5 * 60 * 1000);
        return () => clearInterval(refreshInterval);
    }, [enabled, faceModelsLoaded]);

    // ?? ?곗냽 留ㅼ묶 ?곹깭 異붿쟻 (理쒖냼 3???곗냽 ?숈씪???뺤씤 ?꾩닔) ??
    const consecutiveMatchRef = useRef({ memberId: null, count: 0, lastDescriptor: null });

    // ?ㅼ떆媛??ㅼ틪 猷⑦봽 (2珥덈쭏?? ??3???곗냽 留ㅼ묶 ?꾩닔
    useEffect(() => {
        if (!enabled || !faceModelsLoaded) return;

        const scanForFace = async () => {
            const state = autoUpdateRef.current;
            if (!state.isIdle) return;
            if (state.pin?.length > 0) return;
            if (Date.now() - lastAutoCheckInRef.current < 15000) return;
            if (biometricsCache.current.length === 0) return;

            const video = faceVideoRef.current;
            if (!video || !video.srcObject || video.readyState < 2) return;

            try {
                setIsScanning(true);
                const descriptor = await extractFaceDescriptor(video, true);
                setIsScanning(false);
                if (!descriptor) {
                    // ?쇨뎬 誘멸컧吏 ???곗냽 移댁슫??珥덇린??n                    consecutiveMatchRef.current = { memberId: null, count: 0, lastDescriptor: null };
                    return;
                }

                // ?? ?덉젙??寃利? ?댁쟾 ?꾨젅???붿뒪?щ┰?곗? 鍮꾧탳 ??
                // ?붿뒪?щ┰??蹂?숈씠 ?щ㈃ = ?쇨뎬???吏곸씠怨??덉쓬 ??臾댁떆
                const prevDesc = consecutiveMatchRef.current.lastDescriptor;
                if (prevDesc) {
                    const frameDrift = euclideanDistance(descriptor, prevDesc);
                    if (frameDrift > 0.25) {
                        // ?꾨젅??媛?蹂?숈씠 ?щ㈃ ?쇨뎬???吏곸씠??以???珥덇린??n                        consecutiveMatchRef.current = { memberId: null, count: 0, lastDescriptor: descriptor };
                        return;
                    }
                }

                let bestMatch = null;
                let bestDistance = Infinity;
                let secondBestDistance = Infinity;

                const MATCH_THRESHOLD = 0.42;

                for (const bio of biometricsCache.current) {
                    if (!bio.descriptor) continue;
                    let storedDesc;
                    if (bio.descriptor instanceof Float32Array) {
                        storedDesc = bio.descriptor;
                    } else if (Array.isArray(bio.descriptor)) {
                        storedDesc = new Float32Array(bio.descriptor);
                    } else if (typeof bio.descriptor === 'object') {
                        const keys = Object.keys(bio.descriptor).sort((a,b) => Number(a) - Number(b));
                        storedDesc = new Float32Array(keys.map(k => bio.descriptor[k]));
                    } else {
                        continue;
                    }
                    const distance = euclideanDistance(descriptor, storedDesc);

                    if (distance < bestDistance) {
                        secondBestDistance = bestDistance;
                        bestDistance = distance;
                        bestMatch = bio;
                    } else if (distance < secondBestDistance) {
                        secondBestDistance = distance;
                    }
                }

                const gap = secondBestDistance - bestDistance;
                const isConfidentMatch = bestDistance <= MATCH_THRESHOLD && (
                    gap >= 0.08 || bestDistance <= 0.32
                );

                if (bestMatch && isConfidentMatch) {
                    const prev = consecutiveMatchRef.current;
                    if (prev.memberId === bestMatch.memberId) {
                        // ?? ?곗냽 移댁슫???꾩쟻 ??
                        const newCount = prev.count + 1;
                        consecutiveMatchRef.current = { memberId: bestMatch.memberId, count: newCount, lastDescriptor: descriptor };

                        console.log(`[FACIAL] Consecutive match #${newCount}: ${bestMatch.memberId} (dist=${bestDistance.toFixed(3)}, gap=${gap.toFixed(3)})`);

                        // ?? 3???곗냽 ?뺤씤 ?꾨즺 ??異쒖꽍 泥섎━ ??
                        if (newCount >= 3) {
                            console.log(`[FACIAL] ??CONFIRMED (3 consecutive): ${bestMatch.memberId}`);
                            consecutiveMatchRef.current = { memberId: null, count: 0, lastDescriptor: null };
                            lastAutoCheckInRef.current = Date.now();
                            lastDescriptorRef.current = descriptor;

                            if (attendanceVideoRef?.current && faceVideoRef.current?.srcObject) {
                                try {
                                    if (!attendanceVideoRef.current.srcObject || 
                                        attendanceVideoRef.current.srcObject !== faceVideoRef.current.srcObject) {
                                        attendanceVideoRef.current.srcObject = faceVideoRef.current.srcObject;
                                        await attendanceVideoRef.current.play().catch(() => {});
                                    }
                                } catch (e) {
                                    console.warn('[FACIAL] Could not share stream:', e);
                                }
                            }

                            proceedWithCheckIn(null, false, bestMatch.memberId, null);
                        }
                    } else {
                        // ?? ?ㅻⅨ ?щ엺?쇰줈 諛붾???移댁슫??由ъ뀑 ??
                        consecutiveMatchRef.current = { memberId: bestMatch.memberId, count: 1, lastDescriptor: descriptor };
                        console.log(`[FACIAL] New candidate: ${bestMatch.memberId} (dist=${bestDistance.toFixed(3)}) ??need 2 more`);
                    }
                } else {
                    // 留ㅼ묶 ?ㅽ뙣 ??珥덇린??n                    consecutiveMatchRef.current = { memberId: null, count: 0, lastDescriptor: descriptor };
                    if (bestMatch && bestDistance <= 0.50) {
                        console.log(`[FACIAL] ?좑툘 Weak match ignored: ${bestMatch.memberId} (dist=${bestDistance.toFixed(3)})`);
                    }
                }
            } catch (e) {
                setIsScanning(false);
            }
        };

        scanIntervalRef.current = setInterval(scanForFace, 2000);
        return () => { if (scanIntervalRef.current) clearInterval(scanIntervalRef.current); };
    }, [enabled, faceModelsLoaded, autoUpdateRef, proceedWithCheckIn, attendanceVideoRef]);

    return {
        faceModelsLoaded,
        isScanning,
        faceVideoRef,
        biometricsCache,
        lastDescriptorRef,
        activeTaskIdRef,
        findBestMatch,
    };
}

import { useState, useEffect, useRef } from 'react';
import { storageService } from '../services/storage';

/**
 * useKioskNotice ???ㅼ삤?ㅽ겕 怨듭? ?대?吏 愿由???n * CheckInPage?먯꽌 異붿텧. 吏?먮퀎/?꾩껜 怨듭? 援щ룆 + 5遺??먮룞蹂듭썝 ??대㉧.
 * 
 * @param {Object} options
 * @param {boolean} options.isReady - 珥덇린???꾨즺 ?щ?
 * @param {string} options.currentBranch - ?꾩옱 吏??ID
 * @param {Object|null} options.message - ?꾩옱 硫붿떆吏 ?곹깭
 * @param {boolean} options.showSelectionModal - ?좏깮 紐⑤떖 ?쒖떆 ?щ?
 * @param {boolean} options.showDuplicateConfirm - 以묐났 ?뺤씤 紐⑤떖 ?쒖떆 ?щ?
 * @returns {{ kioskSettings, kioskNoticeHidden, setKioskNoticeHidden }}
 */
export function useKioskNotice({ isReady, currentBranch, message, showSelectionModal, showDuplicateConfirm }) {
    const [kioskSettings, setKioskSettings] = useState({ active: false, imageUrl: null });
    const [kioskNoticeHidden, setKioskNoticeHidden] = useState(false);

    // ?ㅼ삤?ㅽ겕 怨듭? 援щ룆 (吏?먮퀎 ???꾩껜 fallback)
    useEffect(() => {
        if (!isReady) return;

        let unsubscribeBranch = null;
        let unsubscribeAll = null;

        unsubscribeBranch = storageService.subscribeToKioskSettings(currentBranch, (branchData) => {
            if (branchData && branchData.active && branchData.imageUrl) {
                setKioskSettings(branchData);
                setKioskNoticeHidden(false);
            } else {
                unsubscribeAll = storageService.subscribeToKioskSettings('all', (allData) => {
                    if (allData && allData.active && allData.imageUrl) {
                        setKioskSettings(allData);
                        setKioskNoticeHidden(false);
                    } else {
                        setKioskSettings({ active: false, imageUrl: null });
                    }
                });
            }
        });

        return () => {
            if (unsubscribeBranch) unsubscribeBranch();
            if (unsubscribeAll) unsubscribeAll();
        };
    }, [isReady, currentBranch]);

    // 5遺??좏쑕 ?먮룞 蹂듭썝
    useEffect(() => {
        if (!kioskSettings?.active || !kioskNoticeHidden || message || showSelectionModal || showDuplicateConfirm) return;

        let idleTimer;
        const resetNoticeTimer = () => {
            clearTimeout(idleTimer);
            if (kioskNoticeHidden) {
                idleTimer = setTimeout(() => setKioskNoticeHidden(false), 5 * 60 * 1000);
            }
        };

        resetNoticeTimer();
        window.addEventListener('touchstart', resetNoticeTimer, { passive: true });
        window.addEventListener('mousedown', resetNoticeTimer, { passive: true });
        window.addEventListener('keydown', resetNoticeTimer, { passive: true });

        return () => {
            clearTimeout(idleTimer);
            window.removeEventListener('touchstart', resetNoticeTimer);
            window.removeEventListener('mousedown', resetNoticeTimer);
            window.removeEventListener('keydown', resetNoticeTimer);
        };
    }, [kioskSettings?.active, kioskNoticeHidden, message, showSelectionModal, showDuplicateConfirm]);

    return { kioskSettings, kioskNoticeHidden, setKioskNoticeHidden };
}

