 * 
 * face-api.js??detectSingleFace瑜??쒖슜?섏뿬 二쇨린?곸쑝濡??쇨뎬 媛먯?.
 * ?쇨뎬??媛먯??섎㈃ 肄쒕갚???몄텧??異쒖꽍泥댄겕 ?붾㈃?쇰줈 ?먮룞 ?꾪솚.
 * 
 * @param {Object} options
 * @param {boolean} options.enabled - 洹쇱젒 媛먯? ?쒖꽦???щ? (kioskSettings.proximityReturn)
 * @param {boolean} options.isNoticeVisible - 怨듭? ?붾㈃???꾩옱 ?쒖떆 以묒씤吏
 * @param {React.RefObject} options.videoRef - 移대찓??鍮꾨뵒??ref (faceVideoRef)
 * @param {Function} options.onPersonDetected - ?щ엺 媛먯? ???몄텧??肄쒕갚
 */
export function useProximityReturn({ enabled, isNoticeVisible, videoRef, onPersonDetected }) {
    const intervalRef = useRef(null);
    const faceApiRef = useRef(null);
    const cooldownRef = useRef(false);

    useEffect(() => {
        // 議곌굔??留욎? ?딆쑝硫??뺣━
        if (!enabled || !isNoticeVisible) {
            if (intervalRef.current) {
                clearInterval(intervalRef.current);
                intervalRef.current = null;
            }
            return;
        }

        // face-api.js ?숈쟻 濡쒕뱶
        const loadAndStart = async () => {
            try {
                if (!faceApiRef.current) {
                    const faceapi = await import('@vladmandic/face-api');
                    faceApiRef.current = faceapi;
                }

                const faceapi = faceApiRef.current;

                // 紐⑤뜽??濡쒕뱶?섏? ?딆? 寃쎌슦 ??tinyFaceDetector留?濡쒕뱶
                if (!faceapi.nets.tinyFaceDetector.isLoaded) {
                    try {
                        await faceapi.nets.tinyFaceDetector.loadFromUri('/models');
                    } catch (e) {
                        console.warn('[Proximity] Failed to load face detection models:', e);
                        return;
                    }
                }

                // 1珥?媛꾧꺽?쇰줈 ?쇨뎬 媛먯? (??鍮좊Ⅸ 諛섏쓳)
                intervalRef.current = setInterval(async () => {
                    if (cooldownRef.current) return;

                    const video = videoRef?.current;
                    if (!video || video.readyState < 2) return;

                    try {
                        const detection = await faceapi.detectSingleFace(
                            video,
                            new faceapi.TinyFaceDetectorOptions({ inputSize: 320, scoreThreshold: 0.2 })
                        );

                        if (detection) {
                            // 荑⑤떎??(?ㅼ떆 怨듭?媛 ?④퀬 ?섏꽌 諛붾줈 ???몃━??寃?諛⑹?)
                            cooldownRef.current = true;
                            setTimeout(() => { cooldownRef.current = false; }, 10000);

                            onPersonDetected?.();
                        }
                    } catch (e) {
                        // 媛먯? ?ㅽ뙣 臾댁떆
                    }
                }, 1000);
            } catch (e) {
                console.warn('[Proximity] Initialization failed:', e);
            }
        };

        loadAndStart();

        return () => {
            if (intervalRef.current) {
                clearInterval(intervalRef.current);
                intervalRef.current = null;
            }
        };
    }, [enabled, isNoticeVisible, videoRef, onPersonDetected]);
}

import { useMemo } from 'react';
import { getHolidayName } from '../utils/holidays';

export const useRevenueStats = (sales, members, currentDate, currentBranch, revenueStats) => {
    return useMemo(() => {
        const year = currentDate.getFullYear();
        const month = currentDate.getMonth() + 1;
        const monthStr = `${year}-${String(month).padStart(2, '0')}`;

        const allItems = [];
        const salesKeySet = new Set(); // Format: `${memberId}_${date}`
        const seenSalesKeys = new Set(); // Format: `${memberId}_${date}_${amount}`
        const memberIdsWithRegisterSales = new Set(); // [FIX] Members with primary sales records
        const memberNameMap = new Map();
        
        (members || []).forEach(m => memberNameMap.set(m.name, m.id));

        // 1. Process New Sales Data First (Primary Source)
        (sales || []).forEach(s => {
            const resolvedMemberId = s.memberId || memberNameMap.get(s.memberName);
            const member = (members || []).find(m => m.id === resolvedMemberId);
            const saleBranch = s.branchId;
            const memberBranch = member?.homeBranch;

            if (currentBranch !== 'all') {
                // If branch filter applied, check saleBranch FIRST, then memberBranch
                const matchFound = (saleBranch && saleBranch === currentBranch) || 
                                   (!saleBranch && memberBranch && memberBranch === currentBranch);
                if (!matchFound) return;
            }

            // [FIX] Robust date extraction handling both string and Firestore Timestamp
            let dateStr;
            const rawDate = s.date || s.timestamp;
            
            if (!rawDate) {
                console.warn('[Revenue] Sales record missing both date and timestamp:', s.id, s.memberName);
                return;
            }
            
            if (typeof rawDate === 'string' && rawDate.includes('T')) {
                const d = new Date(rawDate);
                dateStr = d.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
            } else if (typeof rawDate === 'object' && rawDate.toDate) {
                // Handle Firestore Timestamp just in case
                dateStr = rawDate.toDate().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
            } else {
                dateStr = String(rawDate); // Fallback string conversion
            }

            // Determine isNew
            let isNew = false;
            if (s.type === 'extend') {
                isNew = false;
            } else if (s.type === 'register' || !s.type) {
                // [FIX] Assume 'register' if type is missing and it matches registration date
                if (member && member.regDate === dateStr) {
                    isNew = true;
                } else {
                    isNew = false;
                }
            }

            const rawAmount = Number(s.amount) || 0;

            // Self Deduplication to match useAdminData.js
            if (resolvedMemberId) {
                const uniqueSaleKey = `${resolvedMemberId}_${dateStr}_${rawAmount}`;
                if (seenSalesKeys.has(uniqueSaleKey)) {
                    return; // Drop duplicate
                }
                seenSalesKeys.add(uniqueSaleKey);
                
                // Track register sales to prevent legacy fallback duplicate
                if (s.type === 'register' || s.type === 'legacy' || (!s.type && isNew)) {
                    memberIdsWithRegisterSales.add(resolvedMemberId);
                }
            }

            const branchId = saleBranch || memberBranch || 'unknown';

            allItems.push({
                id: s.id,
                memberId: resolvedMemberId,
                date: dateStr,
                amount: rawAmount,
                name: s.memberName,
                type: s.type || 'register', // Fallback type
                item: s.item,
                isNew: isNew,
                branchId: branchId
            });

            // Add to dedup set
            if (resolvedMemberId) {
                salesKeySet.add(`${resolvedMemberId}_${dateStr}`);
            }
        });

        // 2. Process Legacy Members Data (Secondary Source)
        // Performance Improvement: Use a Map for O(1) lookups instead of filtering `finalItems` later
        const legacyMemberData = new Map();

        (members || []).forEach(m => {
            const amt = Number(m.amount) || 0;
            if (m.regDate && amt > 0) {
                // Basic validation for reasonable date structure before keeping it
                if (typeof m.regDate !== 'string' || m.regDate.length < 10) return;

                if (currentBranch !== 'all' && m.homeBranch !== currentBranch) return;

                // [FIX] Deduplication Check: Ignore if a register sales record exists for this member
                if (memberIdsWithRegisterSales.has(m.id)) return;
                // Double fallback using legacy matching (just in case they have multiple)
                if (salesKeySet.has(`${m.id}_${m.regDate}`)) return;

                legacyMemberData.set(m.id, {
                    id: m.id,
                    memberId: m.id,
                    date: m.regDate,
                    amount: amt,
                    name: m.name,
                    type: 'legacy',
                    item: m.subject || '?섍컯沅?,
                    isNew: true,
                    branchId: m.homeBranch || 'unknown'
                });
            }
        });

        const finalItems = [...allItems, ...Array.from(legacyMemberData.values())];
        finalItems.sort((a, b) => new Date(b.date) - new Date(a.date));

        // [Debug] Log Revenue Data
        // console.log('Revenue Debug:', {
        //     totalItems: finalItems.length,
        //     sampleItems: finalItems.slice(0, 5)
        // });

        // Optimization: Use a Map to grouping daily amounts for O(1) lookups
        const dailyAmountsMap = new Map();
        finalItems.forEach(item => {
            const currentObj = dailyAmountsMap.get(item.date) || { 
                amount: 0, count: 0, amountNew: 0, amountReReg: 0, amountNewCount: 0, amountReRegCount: 0, salesList: [], branches: {} 
            };
            
            currentObj.amount += item.amount;
            currentObj.count += 1;
            currentObj.salesList.push(item);
            
            const bId = item.branchId || 'unknown';
            currentObj.branches[bId] = (currentObj.branches[bId] || 0) + item.amount;
            
            if (item.isNew) {
                currentObj.amountNew += item.amount;
                currentObj.amountNewCount += 1;
            } else {
                currentObj.amountReReg += item.amount;
                currentObj.amountReRegCount += 1;
            }
            
            dailyAmountsMap.set(item.date, currentObj);
        });

        // 2. Monthly Stats (for Calendar)
        const daily = {};
        const daysInMonth = new Date(year, month, 0).getDate();
        
        // Simple mapping for display
        const holidayMap = {
            'holiday_new_year': '?좎젙',
            'holiday_lunar_new_year': '?ㅻ궇',
            'holiday_samiljeol': '?쇱씪??,
            'holiday_childrens_day': '?대┛?대궇',
            'holiday_buddha': '?앷??꾩떊??,
            'holiday_memorial': '?꾩땐??,
            'holiday_liberation': '愿묐났??,
            'holiday_chuseok': '異붿꽍',
            'holiday_foundation': '媛쒖쿇??,
            'holiday_hangul': '?쒓???,
            'holiday_christmas': '?щ━??, // Shortened for space
            'holiday_election': '?좉굅??
        };

        let monthlyTotal = 0;
        let monthlyNew = 0;
        let monthlyReReg = 0;
        let monthlyCount = 0;

        for (let d = 1; d <= daysInMonth; d++) {
            const dKey = `${monthStr}-${String(d).padStart(2, '0')}`;
            const dateObj = new Date(year, month - 1, d);
            const dayOfWeek = dateObj.getDay(); // 0=Sun
            const holidayRaw = getHolidayName(dKey);
            
            // Fetch aggregated data from map (O(1) instead of filter loop)
            const dayData = dailyAmountsMap.get(dKey) || { 
                amount: 0, count: 0, amountNew: 0, amountReReg: 0, amountNewCount: 0, amountReRegCount: 0, salesList: [] 
            };

            daily[dKey] = {
                date: dKey,
                amount: dayData.amount,
                count: dayData.count,
                amountNew: dayData.amountNew,
                amountReReg: dayData.amountReReg,
                amountNewCount: dayData.amountNewCount,
                amountReRegCount: dayData.amountReRegCount,
                salesList: dayData.salesList,
                isSunday: dayOfWeek === 0,
                isSaturday: dayOfWeek === 6,
                holidayName: holidayRaw ? (holidayMap[holidayRaw] || '怨듯쑕??) : null
            };
            
            monthlyTotal += dayData.amount;
            monthlyNew += dayData.amountNew;
            monthlyReReg += dayData.amountReReg;
            monthlyCount += dayData.count;
        }

        // [FIX] Server Stats Override ?쒓굅 ??revenueStats???좉퇋 留ㅼ텧留?吏묎퀎?섏뿬 遺?뺥솗
        // sales ?곗씠?곗뿉??吏곸젒 怨꾩궛??monthlyTotal/monthlyNew/monthlyReReg媛 ?뺥솗?⑸땲??


        // 3. Comparative Stats (Yesterday, Day Before, Last Week)
        const today = new Date();
        const getOffsetDateString = (offsetDays) => {
            const d = new Date(today);
            d.setDate(today.getDate() - offsetDays);
            return d.toLocaleDateString('sv-SE');
        }

        const todayStr = getOffsetDateString(0);
        const yesterdayStr = getOffsetDateString(1);
        const dayBeforeStr = getOffsetDateString(2);
        const lastWeekStr = getOffsetDateString(7);

        const getDailyTotalOptimized = (dStr) => dailyAmountsMap.get(dStr)?.amount || 0;

        const statYesterday = getDailyTotalOptimized(yesterdayStr);
        const statDayBefore = getDailyTotalOptimized(dayBeforeStr);
        const statToday = getDailyTotalOptimized(todayStr); 
        const statLastWeekStr = getDailyTotalOptimized(lastWeekStr);


        // 4. Trend Graph (Last 14 Days)
        const trendData = [];
        for (let i = 13; i >= 0; i--) {
            const d = new Date(today);
            d.setDate(today.getDate() - i);
            const dStr = d.toLocaleDateString('sv-SE');
            const dayData = dailyAmountsMap.get(dStr) || {};
            trendData.push({
                date: dStr,
                displayDate: `${d.getMonth() + 1}/${d.getDate()}`,
                amount: dayData.amount || 0,
                branches: dayData.branches || {}
            });
        }

        // 5. Monthly Trend (Last 6 Months)
        const monthlyTrendData = [];
        const currentDayOfM = currentDate.getDate(); // 1~31

        for (let i = 5; i >= 0; i--) {
            const d = new Date(year, month - 1 - i, 1);
            const mStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
            const label = `${d.getMonth() + 1}??;
            
            let amount = 0;
            let partialAmount = 0;
            let branches = {};
            let partialBranches = {};

            // [FIX] ??긽 sales ?곗씠?곗뿉??吏곸젒 怨꾩궛 (revenueStats ?쒕쾭 ?듦퀎 ?ъ슜 ????
            dailyAmountsMap.forEach((val, key) => {
                if (key.startsWith(mStr)) {
                    amount += val.amount;
                    const dayPart = parseInt(key.substring(8, 10), 10);
                    if (dayPart <= currentDayOfM) {
                        partialAmount += val.amount;
                    }
                }
            });

            // Always calculate branch amounts from dailyAmountsMap for graphs
            dailyAmountsMap.forEach((val, key) => {
                if (key.startsWith(mStr)) {
                    Object.entries(val.branches || {}).forEach(([bId, amt]) => {
                        branches[bId] = (branches[bId] || 0) + amt;
                        const dayPart = parseInt(key.substring(8, 10), 10);
                        if (dayPart <= currentDayOfM) {
                            partialBranches[bId] = (partialBranches[bId] || 0) + amt;
                        }
                    });
                }
            });

            monthlyTrendData.push({
                name: label,
                monthParams: mStr, 
                amount: amount,
                partialAmount: partialAmount,
                branches,
                partialBranches
            });
        }

        // 6. Membership Type Sales (?뚯썝沅뚮퀎 ?먮ℓ??
        const membershipMap = new Map();
        finalItems.forEach(item => {
            if (!item.date.startsWith(monthStr)) return;
            const key = item.item || '?섍컯沅?;
            const current = membershipMap.get(key) || { name: key, count: 0, revenue: 0, newCount: 0, reregCount: 0 };
            current.count += 1;
            current.revenue += item.amount;
            if (item.isNew) current.newCount += 1;
            else current.reregCount += 1;
            membershipMap.set(key, current);
        });
        const membershipSales = Array.from(membershipMap.values())
            .sort((a, b) => b.count - a.count);

        return {
            dailyStats: Object.values(daily),
            monthlyStats: {
                totalRevenue: monthlyTotal,
                totalRevenueNew: monthlyNew,
                totalRevenueReReg: monthlyReReg,
                totalCount: monthlyCount
            },
            comparativeStats: {
                yesterday: statYesterday,
                dayBefore: statDayBefore,
                today: statToday
            },
            recentTrend: trendData,
            monthlyTrend: monthlyTrendData,
            membershipSales
        };

    }, [members, sales, currentDate, currentBranch, revenueStats]);
};

import { useState, useEffect, useCallback } from 'react';
import { storageService } from '../services/storage';
import * as bookingService from '../services/bookingService';

/**
 * useScheduleData ??AdminScheduleManager ?곗씠??濡쒖쭅 ??n * ?붾퀎 ?ㅼ?以?CRUD, 諛깆뾽/蹂듭썝, 留덉뒪???곗씠??濡쒕뱶 愿由?
 *
 * @param {string} branchId
 * @param {Object} config
 * @returns {{ year, month, loading, monthlyClasses, scheduleStatus, images, instructors, classTypes, classLevels, monthlyBookings, handlePrevMonth, handleNextMonth, loadMonthlyData, handleCreateStandard, handleCopyPrevMonth, handleReset, confirmReset, handleOpenRestore, handleRestoreBackup, saveDayClasses, backupList, showResetConfirm, setShowResetConfirm, showRestoreModal, setShowRestoreModal }}
 */
export function useScheduleData(branchId, config) {
    const today = new Date();
    const [year, setYear] = useState(today.getFullYear());
    const [month, setMonth] = useState(today.getMonth() + 1);
    const [monthlyClasses, setMonthlyClasses] = useState({});
    const [scheduleStatus, setScheduleStatus] = useState('undefined');
    const [images, setImages] = useState({});
    const [loading, setLoading] = useState(false);
    const [instructors, setInstructors] = useState([]);
    const [classTypes, setClassTypes] = useState([]);
    const [classLevels, setClassLevels] = useState([]);
    const [monthlyBookings, setMonthlyBookings] = useState({});
    const [showResetConfirm, setShowResetConfirm] = useState(false);
    const [showRestoreModal, setShowRestoreModal] = useState(false);
    const [backupList, setBackupList] = useState([]);

    const allowBooking = config?.POLICIES?.ALLOW_BOOKING;

    const loadMonthlyData = useCallback(async () => {
        setLoading(true);
        try {
            const status = await storageService.getMonthlyScheduleStatus(branchId, year, month);
            setScheduleStatus(status.exists && status.isSaved ? 'saved' : 'undefined');
            if (status.exists && status.isSaved) {
                const data = await storageService.getMonthlyClasses(branchId, year, month);
                setMonthlyClasses(data);
            } else {
                setMonthlyClasses({});
            }
            const imgs = await storageService.getImages();
            setImages(imgs);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    }, [branchId, year, month]);

    const loadMasterData = useCallback(async () => {
        const [instructorList, classTypeList, classLevelList] = await Promise.all([
            storageService.getInstructors(),
            storageService.getClassTypes(),
            storageService.getClassLevels()
        ]);
        setInstructors(instructorList);
        setClassTypes(classTypeList);
        setClassLevels(classLevelList);
    }, []);

    // 珥덇린??+ ?ㅼ떆媛?援щ룆
    useEffect(() => {
        setScheduleStatus('undefined');
        loadMonthlyData();
        loadMasterData();

        const unsub = storageService.subscribe(async (eventType) => {
            if (eventType === 'images' || eventType === 'all') {
                const latestImages = await storageService.getImages();
                setImages(latestImages);
            }
            if (eventType === 'dailyClasses' || eventType === 'all') loadMonthlyData();
            if (eventType === 'settings' || eventType === 'all') loadMasterData();
        }, ['images', 'dailyClasses', 'settings']);

        return () => unsub();
    }, [branchId, year, month, loadMonthlyData, loadMasterData]);

    // ?덉빟 援щ룆
    useEffect(() => {
        if (!allowBooking) { setMonthlyBookings({}); return; }
        const unsub = bookingService.subscribeMonthBookings(branchId, year, month, (bookings) => {
            const byDate = {};
            bookings.forEach(b => {
                if (!byDate[b.date]) byDate[b.date] = [];
                byDate[b.date].push(b);
            });
            setMonthlyBookings(byDate);
        });
        return () => unsub();
    }, [year, month, branchId, allowBooking]);

    const handlePrevMonth = () => {
        if (month === 1) { setYear(year - 1); setMonth(12); } else setMonth(month - 1);
    };
    const handleNextMonth = () => {
        if (month === 12) { setYear(year + 1); setMonth(1); } else setMonth(month + 1);
    };

    const handleCreateStandard = async () => {
        const confirmMsg = `?뱟 ${year}??${month}?붿뿉 '?쒖? ?쒓컙??湲곕낯)'瑜??곸슜?섏떆寃좎뒿?덇퉴?\n\n湲곕낯 ?ㅼ젙???쒓컙???⑦꽩?쇰줈 ?앹꽦?⑸땲??`;
        if (!window.confirm(confirmMsg)) return;
        setLoading(true);
        try {
            const res = await storageService.createMonthlySchedule(branchId, year, month);
            alert(res.message || "?쒖? ?쒓컙?쒓? ?앹꽦?섏뿀?듬땲??");
            await loadMonthlyData();
        } catch (error) {
            console.error("Error creating standard schedule:", error);
            alert("?앹꽦 以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎: " + error.message);
        } finally { setLoading(false); }
    };

    const handleCopyPrevMonth = async () => {
        const d = new Date(year, month - 1, 1);
        d.setMonth(d.getMonth() - 1);
        const prevYear = d.getFullYear();
        const prevMonth = d.getMonth() + 1;
        if (!confirm(`${prevYear}??${prevMonth}?붿쓽 ?ㅼ?以??⑦꽩??蹂듭궗?섏뿬\n${year}??${month}???ㅼ?以꾩쓣 ?앹꽦?섏떆寃좎뒿?덇퉴?\n\n(?쇱슂?쇨낵 ?좎슂???쇱젙???쒖감?곸쑝濡?蹂듭궗?⑸땲??)`)) return;
        setLoading(true);
        try {
            await storageService.copyMonthlySchedule(branchId, prevYear, prevMonth, year, month);
            alert('?댁쟾 ???댁슜??諛뷀깢?쇰줈 ?ㅼ?以꾩씠 ?앹꽦?섏뿀?듬땲??');
            await loadMonthlyData();
        } catch (e) { console.error(e); alert(e.message); }
        finally { setLoading(false); }
    };

    const handleReset = () => setShowResetConfirm(true);

    const confirmReset = async () => {
        setShowResetConfirm(false);
        setLoading(true);
        try {
            await storageService.deleteMonthlySchedule(branchId, year, month);
            alert('?ㅼ?以꾩씠 珥덇린?붾릺?덉뒿?덈떎.\n(?뱀떆 ?ㅼ닔濡?吏?좊떎硫?[諛깆뾽 蹂듭썝] 踰꾪듉?쇰줈 ?대┫ ???덉뒿?덈떎)');
            await loadMonthlyData();
        } catch (error) {
            console.error("Reset failed:", error);
            alert("珥덇린??以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎: " + error.message);
        } finally { setLoading(false); }
    };

    const handleOpenRestore = async () => {
        setLoading(true);
        try {
            const list = await storageService.getMonthlyBackups(branchId, year, month);
            setBackupList(list);
            setShowRestoreModal(true);
        } catch (e) { alert('諛깆뾽 紐⑸줉??遺덈윭?ㅻ뒗???ㅽ뙣?덉뒿?덈떎.'); }
        finally { setLoading(false); }
    };

    const handleRestoreBackup = async (backupId) => {
        if (!window.confirm('?좏깮???댁쟾 ?ㅼ?以꾨줈 蹂듭썝?섏떆寃좎뒿?덇퉴?\n?꾩옱 ?쒓컙???댁슜????뼱?뚯썙吏묐땲??')) return;
        setShowRestoreModal(false);
        setLoading(true);
        try {
            await storageService.restoreMonthlyBackup(branchId, year, month, backupId);
            alert('?ㅼ?以꾩씠 ?먯긽蹂듦뎄 ?섏뿀?듬땲??');
            await loadMonthlyData();
        } catch (e) { console.error("Restore failed:", e); alert('蹂듭썝 以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎.'); }
        finally { setLoading(false); }
    };

    const saveDayClasses = async (selectedDate, dayClasses, applyToAll = false) => {
        if (!selectedDate) return false;

        // ?? ?쒓컙???뺣젹 (HH:MM 湲곗?) ??
        dayClasses.sort((a, b) => {
            const timeA = a.time || '00:00';
            const timeB = b.time || '00:00';
            return timeA.localeCompare(timeB);
        });

        setLoading(true);
        try {
            let shouldUpdatePastAttendance = false;
            let oldClassesSnapshot = monthlyClasses[selectedDate] || [];
            let hasRelevantChanges = false;
            dayClasses.forEach(newCls => {
                if (!newCls.time) return;
                const oldCls = oldClassesSnapshot.find(c => c.time === newCls.time);
                if (oldCls) {
                    const isTitleChanged = (oldCls.title || oldCls.className) !== (newCls.title || newCls.className);
                    const isInstChanged = oldCls.instructor !== newCls.instructor;
                    if (isTitleChanged || isInstChanged) hasRelevantChanges = true;
                }
            });

            if (hasRelevantChanges && !applyToAll) {
                shouldUpdatePastAttendance = window.confirm(
                    `?대떦 ?좎쭨(${selectedDate})???섏뾽紐낆씠??媛뺤궗紐낆씠 蹂寃쎈릺?덉뒿?덈떎.\n\n` +
                    `??蹂寃??ы빆??怨쇨굅 異쒖꽍 湲곕줉(?대? ?깅줉??異쒖꽍遺)?먮룄 ?쇨큵 ?곸슜?섏떆寃좎뒿?덇퉴?\n` +
                    `(?곸슜 ??媛뺤궗???듦퀎 ?깆씠 ?섏젙?섎ŉ, ?뚯썝???⑥? ?잛닔/湲곌컙? 蹂?숇릺吏 ?딆븘 ?덉쟾?⑸땲??)`
                );
            }

            if (applyToAll) {
                const targetDate = new Date(selectedDate);
                const targetDayIndex = targetDate.getDay();
                const dayNames = ['??, '??, '??, '??, '紐?, '湲?, '??];
                const targetDayName = dayNames[targetDayIndex];
                const datesToUpdate = [];
                const tempDate = new Date(year, month - 1, 1);
                while (tempDate.getMonth() === month - 1) {
                    if (tempDate.getDay() === targetDayIndex) {
                        const dStr = `${tempDate.getFullYear()}-${String(tempDate.getMonth() + 1).padStart(2, '0')}-${String(tempDate.getDate()).padStart(2, '0')}`;
                        datesToUpdate.push({ date: dStr, classes: dayClasses });
                    }
                    tempDate.setDate(tempDate.getDate() + 1);
                }
                if (!window.confirm(`?대쾲 ?ъ쓽 紐⑤뱺 [${targetDayName}?붿씪] (${datesToUpdate.length}?????숈씪?섍쾶 ?섏젙?섏떆寃좎뒿?덇퉴?\n\n?좎쭨: ${datesToUpdate.map(d => d.date.split('-')[2]).join(', ')}`)) {
                    setLoading(false);
                    return false;
                }
                await storageService.batchUpdateDailyClasses(branchId, datesToUpdate);
                if (shouldUpdatePastAttendance) {
                    for (const dateObj of datesToUpdate) {
                        const oldClassesForDate = monthlyClasses[dateObj.date] || [];
                        await storageService.updatePastAttendanceRecords(branchId, dateObj.date, oldClassesForDate, dateObj.classes);
                    }
                }
            } else {
                await storageService.updateDailyClasses(branchId, selectedDate, dayClasses);
                if (shouldUpdatePastAttendance) {
                    await storageService.updatePastAttendanceRecords(branchId, selectedDate, oldClassesSnapshot, dayClasses);
                }
            }
            await loadMonthlyData();
            return true;
        } catch (error) {
            console.error("Error saving daily classes:", error);
            alert("???以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎.");
            return false;
        } finally { setLoading(false); }
    };

    return {
        year, month, loading, monthlyClasses, scheduleStatus, images,
        instructors, setInstructors, classTypes, setClassTypes, classLevels, setClassLevels,
        monthlyBookings, handlePrevMonth, handleNextMonth, loadMonthlyData,
        handleCreateStandard, handleCopyPrevMonth, handleReset, confirmReset,
        handleOpenRestore, handleRestoreBackup, saveDayClasses,
        backupList, showResetConfirm, setShowResetConfirm, showRestoreModal, setShowRestoreModal,
    };
}

