    const [showInstructorQR, setShowInstructorQR] = useState(false);
    const [keypadLocked, setKeypadLocked] = useState(false);
    const [showFaceRegModal, setShowFaceRegModal] = useState(false);
    const [showDuplicateConfirm, setShowDuplicateConfirm] = useState(false);
    const [showKioskInstallGuide, setShowKioskInstallGuide] = useState(false);
    const [pendingPin, setPendingPin] = useState(null);
    const [duplicateTimer, setDuplicateTimer] = useState(config.POLICIES?.SESSION_AUTO_CLOSE_SEC || 25);
    const [isDuplicateFlow, setIsDuplicateFlow] = useState(false);
    const [loadingMessage, setLoadingMessage] = useState('異쒖꽍 ?뺤씤 以?..');
    const [period, setPeriod] = useState(() => {
        const h = getKSTHour();
        if (h >= 6 && h < 12) return 'morning';
        if (h >= 12 && h < 17) return 'afternoon';
        if (h >= 17 && h < 21) return 'evening';
        return 'night';
    });
    const [bgImage, setBgImage] = useState(null);
    const [monthlyClasses, setMonthlyClasses] = useState({});
    const [isOnline, setIsOnline] = useState(true);

    // Refs
    const timerRef = useRef(null);
    const duplicateAutoCloseRef = useRef(null);
    const recentCheckInsRef = useRef([]);
    const autoUpdateRef = useRef({ isIdle: true, pin: '' });
    const pinRef = useRef(pin);
    const warmupTriggered = useRef(false);

    // Custom Hooks
    const pwaContext = usePWA();
    const { checkConnection } = useNetworkMonitor();
    const { speak } = useTTS();
    const photoEnabled = config.POLICIES?.PHOTO_ENABLED === true || faceRecognitionEnabled === true;
    const { videoRef, canvasRef, capturePhoto, uploadPhoto, stream: cameraStream } = useAttendanceCamera(photoEnabled);

    const {
        faceModelsLoaded, isScanning, faceVideoRef,
        lastDescriptorRef, activeTaskIdRef, findBestMatch
    } = useFacialRecognition({
        enabled: faceRecognitionEnabled,
        autoUpdateRef,
        attendanceVideoRef: videoRef, // ?ъ쭊 罹≪쿂??移대찓??怨듭쑀
        proceedWithCheckIn: useCallback((pin, isDup, memberId, task) => {
            proceedWithCheckIn(pin, isDup, memberId, task);
        }, []),
    });

    const { kioskSettings, kioskNoticeHidden, setKioskNoticeHidden } = useKioskNotice({
        isReady, currentBranch, message, showSelectionModal, showDuplicateConfirm
    });

    // 洹쇱젒 媛먯?: 怨듭? ?붾㈃ ?쒖떆 以?+ ?듭뀡 ON?대㈃ 移대찓?쇰줈 ?쇨뎬 媛먯? ???먮룞 ?꾪솚
    const isNoticeVisible = !!(kioskSettings?.active && kioskSettings?.imageUrl && !kioskNoticeHidden && !message);
    useProximityReturn({
        enabled: !!kioskSettings?.proximityReturn,
        isNoticeVisible,
        videoRef: faceVideoRef,
        onPersonDetected: useCallback(() => setKioskNoticeHidden(true), [setKioskNoticeHidden])
    });

    const language = CHECKIN_CONFIG.LOCALE;
    const qrCodeUrl = `${CHECKIN_CONFIG.ASSETS.QR_CODE_BASE_URL}?${CHECKIN_CONFIG.ASSETS.QR_CODE_PARAMS}&data=${encodeURIComponent(window.location.origin + '/member')}`;

    const warmupFunctions = useCallback(() => {
        if (warmupTriggered.current) return;
        warmupTriggered.current = true;
        import('firebase/functions').then(({ httpsCallable }) => {
             import('../firebase').then(({ functions }) => {
                 const checkInCall = httpsCallable(functions, 'checkInMemberV2Call');
                 checkInCall({ ping: true }).catch(() => {});
                 const loginCall = httpsCallable(functions, 'memberLoginV2Call');
                 loginCall({ ping: true }).catch(() => {});
             }).catch(() => {});
        }).catch(() => {});
    }, []);

    // ?? Effects ??
    useEffect(() => { 
        // [洹쇰낯 ?섏젙] ?ㅼ삤?ㅽ겕媛 ?좏쑕 ?곹깭?몄? ?섎굹??boolean?쇰줈 ?듯빀 ?먮떒
        // ?대뼡 紐⑤떖/?ㅻ쾭?덉씠/濡쒕뵫?대뱺 ?섎굹?쇰룄 ?쒖꽦?대㈃ isIdle = false
        const isIdle = !message && !loading && !showSelectionModal && !showDuplicateConfirm 
            && !showFaceRegModal && !showInstructorQR && !showKioskInstallGuide;
        autoUpdateRef.current = { isIdle, pin };
        pinRef.current = pin;
    }, [pin, message, loading, showSelectionModal, showDuplicateConfirm, showFaceRegModal, showInstructorQR, showKioskInstallGuide]);

    useEffect(() => {
        const init = async () => {
            try { await signInAnonymously(auth); } catch (e) {}
            await storageService.initialize({ mode: 'kiosk' });
            setIsReady(true);
            fetchWeatherAndAI();
        };
        init();
        const vh = () => document.documentElement.style.setProperty('--vh', `${window.innerHeight * 0.01}px`);
        vh(); window.addEventListener('resize', vh);

        let unsubClasses = () => {};
        if (currentBranch) {
            const todayCurrent = new Date();
            unsubClasses = subscribeMonthlyClasses(
                currentBranch, todayCurrent.getFullYear(), todayCurrent.getMonth() + 1,
                (data) => setMonthlyClasses(data || {})
            );
        }

        return () => { unsubClasses(); window.removeEventListener('resize', vh); };
    }, []);

    // [PWA] ?ㅼ삤?ㅽ겕 ???덊솕硫??ㅼ튂 ?좊룄 ?먮룞 ?앹뾽 - ?쒓굅 (?곗튂 ?덊빐??媛묒옄湲??⑤뒗 踰꾧렇 ?먯씤)
    useEffect(() => {
        // ?먮룞 ?앹뾽???쒓굅?섏뿬 ?붾㈃??諛⑺빐?섏? ?딅룄濡???(QR 肄붾뱶 ?대┃ ?쒖뿉留??섎룞?쇰줈 ??
    }, [isReady, pwaContext.isStandalone]);

    useEffect(() => { setBgImage(getBgForPeriod(period)); }, [period]);

    // ?? Business Logic ??
    const loadAIExperience = async (name = "諛⑸Ц ?뚯썝", credits = null, days = null, w = null) => {
        const isStandby = name === "諛⑸Ц ?뚯썝";
        try {
            const h = getKSTHour();
            if (h < CHECKIN_CONFIG.SERVICE_HOURS.AI_READY_START || h >= CHECKIN_CONFIG.SERVICE_HOURS.AI_READY_END) {
                setAiExperience({ message: AIMessages.FALLBACK_MESSAGE_OUTSIDE_BUSINESS_HOURS, isFallback: true });
                return;
            }
            const info = await storageService.getCurrentClass(currentBranch);
            const title = info?.title || "?먯쑉?섎젴";
            if (isStandby) {
                const staticMsg = getStaticStandbyMessage(h, w?.weathercode || '0', title);
                setAiExperience({ message: staticMsg, isFallback: true });
                setAiLoading(true);
                storageService.getAIExperience(name, 0, '?ㅻ뒛', h, title, w, null, null, language, null, 'visitor', 'checkin')
                    .then(res => { if (res?.message && !res.isFallback) setAiEnhancedMsg(res.message.replace(/?섎쭏?ㅽ뀒[.]?\s*?솋?/gi, '').trim()); })
                    .finally(() => setAiLoading(false));
            } else {
                const exp = await storageService.getAIExperience(name, 0, '?ㅻ뒛', h, title, w, credits, days, language, null, 'member', 'checkin');
                if (exp) setAiExperience({ ...exp, message: exp.message.replace(/?섎쭏?ㅽ뀒[.]?\s*?솋?/gi, '').trim() });
            }
        } catch (e) {}
    };

    const fetchWeatherAndAI = async () => {
        try {
            const r = await fetch('https://api.open-meteo.com/v1/forecast?latitude=37.5665&longitude=126.9780&current_weather=true');
            const d = await r.json();
            setWeather(d.current_weather);
            loadAIExperience("諛⑸Ц ?뚯썝", null, null, d.current_weather);
        } catch (e) { loadAIExperience(); }
    };

    const handleModalClose = useCallback((action) => {
        setKeypadLocked(true);
        action();
        setPin('');
        setAiEnhancedMsg(null);
        setAiLoading(false);
        setTimeout(() => setKeypadLocked(false), 350);
    }, []);

    const showCheckInSuccess = async (res, isDup = false) => {
        const m = res.member;
        const credits = m.credits ?? 0;
        let daysLeft = 999;
        if (m.endDate) {
            const end = safeParseDate(m.endDate);
            const now = new Date(); now.setHours(0,0,0,0); end.setHours(0,0,0,0);
            daysLeft = Math.ceil((end - now) / 86400000);
        }

        let msg = "?ㅻ뒛???섎젴???쒖옉?⑸땲??";
        let isConsecutive = false;
        let isExtra = false;

        if (res.isDuplicate) {
            isExtra = true;
        } else if (res.sessionCount && res.sessionCount > 1) {
            isExtra = isDup;
            isConsecutive = !isDup;
        }

        if (isExtra) { msg = "諛섍??뚯슂! ?대? 異쒖꽍 ?뺤씤???꾨즺?섏뿀?듬땲?? (異붽? 異쒖꽍)"; speak("success_extra"); }
        else if (isConsecutive) { msg = "?ㅻ뒛????踰덉㎏ ?섎젴???쒖옉?⑸땲?? (?곌컯 異쒖꽍)"; speak("success_consecutive"); }
        else if (daysLeft < 0) { msg = "?섎젴沅?湲곌컙??留뚮즺?섏뿀?듬땲?? ?좎깮?섍퍡???덈궡瑜??꾩??쒕┫寃뚯슂."; speak("denied"); }
        else if (credits < 0) { msg = "?섎젴 ?잛닔媛 紐⑤몢 ?뚯쭊?섏뿀?듬땲?? ?좎깮?섍퍡???덈궡瑜??꾩??쒕┫寃뚯슂."; speak("denied"); }
        else if (credits === 0 || daysLeft === 0) { msg = "?ㅻ뒛???대쾲 ?섎젴沅뚯쓽 留덉?留??좎씠?ㅼ슂. ?뺤꽦 媛?앺븳 ?섎젴 ?섏꽭??"; speak("last_session"); }
        else { speak("success"); }

        await new Promise(r => setTimeout(r, 100));
        setMessage({ type: 'success', member: m, text: `${m.name}??, subText: msg });
        if (timerRef.current) clearTimeout(timerRef.current);
        timerRef.current = setTimeout(() => handleModalClose(() => setMessage(null)), CHECKIN_CONFIG.TIMEOUTS.SUCCESS_MODAL);
        setAiEnhancedMsg("?ㅻ뒛???됱삩???붽? ?덈궡???쒕┫寃뚯슂. ?섎쭏?ㅽ뀒 ?솋");
        setAiLoading(false);
    };

    const proceedWithCheckIn = async (p, isDup = false, memberIdToForce = null, facialTask = null) => {
        setLoading(true);
        recentCheckInsRef.current.push({ pin: p, timestamp: Date.now() });
        try {
            if (facialTask && !lastDescriptorRef.current) {
                try {
                    const timeout = new Promise((_, reject) => setTimeout(() => reject(new Error('timeout')), 1500));
                    await Promise.race([facialTask, timeout]);
                } catch (e) {}
            }

            let targetMemberId = memberIdToForce;
            let isFacialMatch = false;

            if (!targetMemberId) {
                let members = [];
                try { members = await storageService.findMembersByPhone(p); }
                catch (lookupErr) { members = []; }

                if (members.length === 0) {
                    speak("error");
                    await new Promise(r => setTimeout(r, 300));
                    setMessage({ type: 'error', text: '?뚯썝 ?뺣낫瑜?李얠쓣 ???놁뒿?덈떎.' });
                    return;
                }
                if (members.length > 1) {
                    // [FIX] 鍮꾪솢???뚯썝 ?쒖쇅 (?섍컯沅?留뚮즺/?잛닔 ?뚯쭊)
                    const activeMembers = members.filter(m => isMemberActive(m));
                    const candidateMembers = activeMembers.length > 0 ? activeMembers : members;

                    if (candidateMembers.length === 1) {
                        // ?쒖꽦 ?뚯썝??1紐낅퓧?대㈃ 諛붾줈 ?좏깮
                        targetMemberId = candidateMembers[0].id;
                    } else if (candidateMembers.length > 1) {
                        // [FIX] ?꾩썝 ?덈㈃ ?곗씠?곌? ?덉쓣 ?뚮쭔 ?먮룞 ?먮떒
                        const allHaveFace = candidateMembers.every(m =>
                            (m.faceDescriptors && m.faceDescriptors.length > 0) || m.faceDescriptor
                        );

                        if (allHaveFace && faceModelsLoaded && lastDescriptorRef.current) {
                            const bestMatch = findBestMatch(lastDescriptorRef.current, candidateMembers);
                            if (bestMatch) {
                                const { euclideanDistance } = await import('../services/facialService');
                                let secondBestDist = 999;
                                const bestDesc = bestMatch.faceDescriptors?.[0]
                                    ? new Float32Array(bestMatch.faceDescriptors[0])
                                    : bestMatch.faceDescriptor
                                        ? new Float32Array(Object.values(bestMatch.faceDescriptor))
                                        : null;
                                const bestDist = bestDesc ? euclideanDistance(lastDescriptorRef.current, bestDesc) : 999;
                                for (const m of candidateMembers) {
                                    if (m.id === bestMatch.id) continue;
                                    const desc = m.faceDescriptors?.[0]
                                        ? new Float32Array(m.faceDescriptors[0])
                                        : m.faceDescriptor
                                            ? new Float32Array(Object.values(m.faceDescriptor))
                                            : null;
                                    if (desc) {
                                        const d = euclideanDistance(lastDescriptorRef.current, desc);
                                        if (d < secondBestDist) secondBestDist = d;
                                    }
                                }
                                const gap = secondBestDist - bestDist;
                                if (gap > 0.15) {
                                    targetMemberId = bestMatch.id;
                                    isFacialMatch = true;
                                }
                            }
                        }
                        // ?먮룞 ?먮떒 紐??덉쑝硫????좏깮 紐⑤떖
                        if (!targetMemberId) {
                            setDuplicateMembers(candidateMembers);
                            setIsDuplicateFlow(isDup);
                            setShowSelectionModal(true);
                            return;
                        }
                    }
                } else {
                    targetMemberId = members[0].id;
                }
            }

            const safeUUID = () => (typeof crypto !== 'undefined' && crypto.randomUUID) ? crypto.randomUUID() : 'id_' + Date.now().toString(36) + Math.random().toString(36).substr(2, 5);
            const source = (memberIdToForce && !p) ? 'facial' : 'pin';
            const res = await storageService.checkInById(targetMemberId, currentBranch, isDup, safeUUID(), isFacialMatch, source);
            if (res.success) {
                setIsOnline(!res.isOffline);
                if (res.attendanceStatus === 'denied') {
                    uploadPhoto(res.attendanceId, res.member?.name, 'denied');
                    speak("denied");
                    await new Promise(r => setTimeout(r, 300));
                    setMessage({ type: 'error', text: '湲곌컙 ?뱀? ?잛닔媛 留뚮즺?섏뿀?듬땲??' });
                } else {
                    uploadPhoto(res.attendanceId, res.member?.name, 'valid');
                    await showCheckInSuccess(res, isDup);
                    if (faceModelsLoaded && lastDescriptorRef.current) {
                        memberService.updateFaceDescriptor(targetMemberId, lastDescriptorRef.current);
                    }
                }
            } else {
                speak("error");
                await new Promise(r => setTimeout(r, 300));
                setMessage({ type: 'error', text: res.message });
            }
        } catch (e) {
            storageService.logError(e, { context: 'Kiosk', branch: currentBranch });
            speak("error");
            setMessage({ type: 'error', text: '?쒖뒪???ㅻ쪟媛 諛쒖깮?덉뒿?덈떎. ?ㅼ떆 ?쒕룄?댁＜?몄슂.' });
        }
        finally { setLoading(false); }
    };

    const handleSubmit = useCallback((p) => {
        const pinCode = typeof p === 'string' ? p : pinRef.current;
        if (pinCode.length !== 4 || loading) return;

        const taskId = ++activeTaskIdRef.current;
        let facialTask = null;
        if (faceModelsLoaded && videoRef.current) {
            facialTask = extractFaceDescriptor(videoRef.current).then(desc => {
                if (taskId === activeTaskIdRef.current) { lastDescriptorRef.current = desc; return desc; }
                return null;
            });
        }

        setTimeout(() => capturePhoto(), 0);

        const duplicateThresholdMs = 20000;
        const isDup = recentCheckInsRef.current.some(e => e.pin === pinCode && (Date.now() - e.timestamp) < duplicateThresholdMs);

        if (isDup) {
            setPendingPin(pinCode);
            setShowDuplicateConfirm(true);
            setDuplicateTimer(config.POLICIES?.SESSION_AUTO_CLOSE_SEC || 25);
            if (duplicateAutoCloseRef.current) clearInterval(duplicateAutoCloseRef.current);
            duplicateAutoCloseRef.current = setInterval(() => setDuplicateTimer(v => v - 1), 1000);
        } else {
            proceedWithCheckIn(pinCode, false, null, facialTask);
        }
    }, [loading, currentBranch, config.POLICIES, faceModelsLoaded, capturePhoto]);

    const handleKeyPress = useCallback((n) => {
        setPin(prev => {
            const next = prev + n;
            return next.length <= 4 ? next : prev;
        });

        if (pinRef.current.length === 0) { 
            setTimeout(() => { checkConnection(); warmupFunctions(); }, 50);
            setTimeout(() => capturePhoto(), 300);
        }

        const nextLength = pinRef.current.length + 1;
        if (nextLength === 4) {
            const finalPin = pinRef.current + n;
            setTimeout(() => handleSubmit(finalPin), 80);
        }
    }, [handleSubmit, checkConnection, faceModelsLoaded, capturePhoto, warmupFunctions]);

    const handleClear = useCallback(() => { setPin(p => p.slice(0, -1)); }, []);

    const closeMessage = useCallback(() => {
        if (timerRef.current) { clearTimeout(timerRef.current); timerRef.current = null; }
        handleModalClose(() => setMessage(null));
    }, [handleModalClose]);

    useAlwaysOnGuardian(isReady);

    useEffect(() => { 
        if (!showDuplicateConfirm) {
            if (duplicateAutoCloseRef.current) { clearInterval(duplicateAutoCloseRef.current); duplicateAutoCloseRef.current = null; }
            return;
        }
        if (duplicateTimer <= 0) { setShowDuplicateConfirm(false); proceedWithCheckIn(pendingPin, true); } 
    }, [duplicateTimer, showDuplicateConfirm, pendingPin]);

    // ?? Render ??
    return (
        <div className="checkin-wrapper" style={{ position: 'relative', width: '100%', height: 'calc(var(--vh, 1vh) * 100)', minHeight: '100vh', overflow: 'hidden', display: 'flex', flexDirection: 'column', background: '#000' }}>
            <div className="bg-container" style={{ position: 'fixed', inset: 0, zIndex: 0 }}>
                <img src={bgImage} alt="bg" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.5)' }} />
            </div>

            <TopBar weather={weather} currentBranch={currentBranch} branches={branches} handleBranchChange={c => { setCurrentBranch(c); storageService.setKioskBranch(c); }} toggleFullscreen={() => { try { const el = document.documentElement; const isFs = document.fullscreenElement || document.webkitFullscreenElement || document.mozFullScreenElement; if (!isFs) { (el.requestFullscreen || el.webkitRequestFullscreen || el.mozRequestFullScreen || (() => {})).call(el); } else { (document.exitFullscreen || document.webkitExitFullscreen || document.mozCancelFullScreen || (() => {})).call(document); } } catch(e) { console.warn('[Fullscreen] Not supported:', e.message); } }} language="ko" onInstructorClick={() => setShowInstructorQR(true)} />

            <div className="checkin-content" style={{ zIndex: 5, flex: 1, display: 'flex', gap: '2vh', padding: '3vh 3vw 5vh', width: '100%', alignItems: 'stretch', overflow: 'hidden' }}>
                <CheckInInfoSection pin={pin} loading={loading} aiExperience={aiExperience} aiEnhancedMsg={aiEnhancedMsg} aiLoading={aiLoading} rys200Logo={rys200Logo} logoWide={logoWide} qrCodeUrl={qrCodeUrl} handleQRInteraction={() => setShowKioskInstallGuide(true)} onCameraTouch={() => setShowFaceRegModal(true)} faceRecognitionEnabled={faceRecognitionEnabled} isScanning={isScanning} cameraVideoRef={faceVideoRef} cameraStream={cameraStream} attendanceVideoRef={videoRef} />
                <CheckInKeypadSection pin={pin} loading={loading} isReady={isReady} loadingMessage={loadingMessage} keypadLocked={keypadLocked} showSelectionModal={showSelectionModal} message={message} handleKeyPress={handleKeyPress} handleClear={handleClear} handleSubmit={handleSubmit} />
            </div>

            <SelectionModal show={showSelectionModal} duplicateMembers={duplicateMembers} loading={loading} onClose={() => { setShowSelectionModal(false); setPin(''); }} onSelect={id => { setShowSelectionModal(false); proceedWithCheckIn(pin, isDuplicateFlow, id); }} />
            <MessageOverlay message={message} onClose={closeMessage} aiExperience={aiExperience} />
            <DuplicateConfirmModal show={showDuplicateConfirm} duplicateTimer={duplicateTimer} onCancel={() => { setShowDuplicateConfirm(false); setPin(''); }} onConfirm={() => { setShowDuplicateConfirm(false); proceedWithCheckIn(pendingPin, true); }} />

            {kioskSettings?.active && kioskSettings?.imageUrl && !kioskNoticeHidden && !message && (
                <div onClick={() => setKioskNoticeHidden(true)} style={{ position: 'fixed', inset: 0, backgroundColor: '#000', zIndex: 2000, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>
                    {(kioskSettings.mediaType === 'video' || kioskSettings.imageUrl.match(/notice_video\.|\.mp4|\.webm|\.mov/i)) ? (
                        <video src={kioskSettings.imageUrl} autoPlay loop muted playsInline style={{ maxWidth: '100%', maxHeight: '100%', objectFit: 'contain' }} />
                    ) : (
                        <img src={kioskSettings.imageUrl} alt="notice" style={{ maxWidth: '100%', maxHeight: '100%', objectFit: 'contain' }} />
                    )}
                    {kioskSettings.showTouchGuide !== false && (
                        <div style={{ position: 'absolute', bottom: '6vh', background: 'rgba(0, 0, 0, 0.85)', color: 'white', padding: '16px 36px', borderRadius: '50px', fontSize: '1.6rem', fontWeight: 'bold', border: '3px solid rgba(var(--primary-rgb), 0.7)', backdropFilter: 'blur(8px)', display: 'flex', alignItems: 'center', gap: '12px', boxShadow: '0 8px 32px rgba(0,0,0,0.5)', pointerEvents: 'none' }}>
                            <span style={{ fontSize: '2rem' }}>?몘</span> ?붾㈃???곗튂?섎㈃ 異쒖꽍遺濡??대룞?⑸땲??n                        </div>
                    )}
                </div>
            )}

            <KioskInstallGuideModal isOpen={showKioskInstallGuide} onClose={() => setShowKioskInstallGuide(false)} />
            <InstructorQRModal isOpen={showInstructorQR} onClose={() => setShowInstructorQR(false)} />
            <FaceRegistrationModal isOpen={showFaceRegModal} onClose={() => setShowFaceRegModal(false)} videoRef={faceVideoRef} modelsAlreadyLoaded={faceModelsLoaded} />
            <a href="/privacy" target="_blank" rel="noopener noreferrer" style={{ position: 'fixed', bottom: '8px', left: '50%', transform: 'translateX(-50%)', fontSize: '0.55rem', color: 'rgba(255,255,255,0.15)', textDecoration: 'none', zIndex: 5, letterSpacing: '0.5px' }}>媛쒖씤?뺣낫泥섎━諛⑹묠</a>
            <video ref={videoRef} autoPlay playsInline muted style={{ position: 'fixed', left: '0', top: '0', width: '1px', height: '1px', opacity: 0.01, zIndex: -100, pointerEvents: 'none' }} />
            <video ref={faceVideoRef} autoPlay playsInline muted style={{ position: 'fixed', left: '-9999px', width: '1px', height: '1px', opacity: 0.01, zIndex: -100, pointerEvents: 'none' }} />
            <canvas ref={canvasRef} style={{ position: 'fixed', left: '0', top: '0', width: '1px', height: '1px', opacity: 0.01, zIndex: -100, pointerEvents: 'none' }} />
        </div>
    );
};

export default CheckInPage;

/**
 * [BUILD-FIX] Attach unminifiable property to component object to defeat tree-shaking
 * This guarantees Rollup will generate a new chunk hash, forcing Workbox to update!
 */
CheckInPage.__buildVersion = `2026.03.20.${Date.now()}`;

import { useState, useEffect, useMemo, useRef } from 'react';
import { CaretLeft, CaretRight, User, SignOut, DotsThreeVertical, List, X, House, Calendar, ChatCircleText, Table, UsersFour, ChartBar, Bell, BellSlash, SpinnerGap, CalendarBlank } from '@phosphor-icons/react';
import { useStudioConfig } from '../contexts/StudioContext';
import { storageService } from '../services/storage';
import { getKSTHour, getKSTDayOfWeek } from '../utils/dates';
import { auth } from '../firebase';
import { onAuthStateChanged } from 'firebase/auth';
import CosmicParticles from '../components/common/CosmicParticles';

import InstructorLogin from '../components/instructor/InstructorLogin';
import InstructorSchedule from '../components/instructor/InstructorSchedule';
import InstructorNotices from '../components/instructor/InstructorNotices';
import InstructorHome from '../components/instructor/InstructorHome';
import InstallGuideModal from '../components/InstallGuideModal';
import InstallBanner from '../components/common/InstallBanner';

// === Helper for Default Greeting ===
const getDefaultGreeting = (name, h, day) => {
    const timeGreeting = h < 12 ? '醫뗭? ?꾩묠?댁뿉?? : h < 17 ? '?ㅻ뒛??醫뗭? ?ㅽ썑?덉슂' : '?섍퀬?섏뀲?댁슂';
    const dayContext = day === '?? ? '?덈줈????二쇱쓽 ?쒖옉!' : 
                      day === '湲? ? '利먭굅??湲덉슂??' : 
                      (day === '?? || day === '??) ? '?됰났??二쇰쭚!' : '';
    return `${name} ?좎깮?? ${timeGreeting} ?쭣?띯?截?${dayContext}`;
};

// === Main Page ===
const InstructorPage = () => {
    const { config } = useStudioConfig();
    const [instructorName, setInstructorName] = useState(localStorage.getItem('instructorName') || '');
    const [instructors, setInstructors] = useState([]);
    const [activeTab, setActiveTab] = useState('home');
    const [loading, setLoading] = useState(true);
    
    // Subscription Cleanup Ref
    const unsubscribesRef = useRef([]);
    const lastAiFetchArgs = useRef(''); // [FIX] AI 以묐났 ?몄텧 諛⑹????곹깭 異붿쟻

    // AI Greeting State (Global)
    const [aiGreeting, setAiGreeting] = useState('');
    const [aiGreetingLoading, setAiGreetingLoading] = useState(false); // [AI] 濡쒕뵫 ?좊땲硫붿씠??r
    const [aiEnhancedGreeting, setAiEnhancedGreeting] = useState(null); // [AI] AI 蹂닿컯 硫붿떆吏
    const [showInstallGuide, setShowInstallGuide] = useState(false); // [PWA] Install Guide
    const [pushEnabled, setPushEnabled] = useState('Notification' in window && Notification.permission === 'granted');
    const [pushLoading, setPushLoading] = useState(false);
    
    // Attendance State (Global)
    const [attendance, setAttendance] = useState([]);
    const [instructorClasses, setInstructorClasses] = useState([]);
    const [attendanceLoading, setAttendanceLoading] = useState(true);
    const todayStr = useMemo(() => new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }), []);
    const hour = getKSTHour();

    const branches = config.BRANCHES || [];

    // Load Instructors
    useEffect(() => {
        const loadInstructors = async () => {
            try {
                const insts = await storageService.getInstructors();
                if (insts && insts.length > 0) {
                    setInstructors(insts);
                    
                    // [DEMO] ?곕え ?ъ씠??泥?吏꾩엯 ???ㅼ젣 ?깅줉??泥?踰덉㎏ 媛뺤궗濡??먮룞 濡쒓렇??(洹쇰낯???닿껐)
                    const isDemoSite = window.location.hostname.includes('passflow-demo') || localStorage.getItem('lastStudioId') === 'demo-yoga';
                    if (isDemoSite && !localStorage.getItem('instructorName') && !sessionStorage.getItem('demoLogout')) {
                        const firstInst = typeof insts[0] === 'string' ? insts[0] : insts[0].name;
                        localStorage.setItem('instructorName', firstInst);
                        setInstructorName(firstInst);
                    }
                }
            } catch (e) {
                console.error('Failed to load instructors:', e);
            } finally {
                setLoading(false);
            }
        };
        loadInstructors();
    }, []);

    // [Deep Link] Parse 'tab' from URL to auto-navigate
    useEffect(() => {
        const handleLocationChange = () => {
            const params = new URLSearchParams(window.location.search);
            const tab = params.get('tab');
            
            if (tab && ['home', 'schedule', 'notices'].includes(tab)) {
                console.log(`[InstructorPage] Navigating to tab: ${tab}`);
                setActiveTab(tab);
                
                // Clear the query param after use so browser reload returns to home
                setTimeout(() => {
                    const newUrl = window.location.pathname;
                    window.history.replaceState({}, '', newUrl);
                }, 500);
            }
        };

        // Initial check
        handleLocationChange();

        // Listen for history changes
        window.addEventListener('popstate', handleLocationChange);

        // [FIX] ?대깽??湲곕컲 deep link 媛먯? (setInterval ?대쭅 ?쒓굅 ???깅뒫 媛쒖꽑)
        window.addEventListener('hashchange', handleLocationChange);

        return () => {
            window.removeEventListener('popstate', handleLocationChange);
            window.removeEventListener('hashchange', handleLocationChange);
        };
    }, []);

    // [PWA] Install Guide State is handled via InstallBanner component now.

    // [PUSH] Auto-register push token ??Auth媛 以鍮꾨맂 ?꾩뿉留??ㅽ뻾
    useEffect(() => {
        if (!instructorName) return;
        
        // [ROOT FIX] onAuthStateChanged濡?Auth 以鍮??뺤씤 ??push ?깅줉
        // setTimeout 3珥?hack ?쒓굅 ??auth ?대깽??湲곕컲?쇰줈 ?뺤떎?섍쾶
        const unsubAuth = onAuthStateChanged(auth, async (user) => {
            if (!user) return; // Auth ?꾩쭅 ??????湲곕떎由?r
            
            try {
                if ('Notification' in window && Notification.permission === 'granted') {
                    console.log(`[InstructorPage] Auth ready (${user.uid}), registering push for: ${instructorName}`);
                    await storageService.requestInstructorPushPermission(instructorName);
                }
            } catch (e) {
                console.error('[InstructorPage] Push registration failed:', e);
            }
            
            // ??踰덈쭔 ?ㅽ뻾 ??由ъ뒪???뺣━
            unsubAuth();
        });
        
        return () => unsubAuth();
    }, [instructorName]);

    // Load Attendance & Schedule in Real-time
    useEffect(() => {
        if (!instructorName) return;

        // 1. Initial Load for Classes & Attendance (Baseline)
        const loadInitialData = async () => {
            try {
                // Fetch Classes (Static for the day)
                const classPromises = branches.map(b => storageService.getDailyClasses(b.id, instructorName, todayStr));
                
                // Fetch Attendance (Baseline)
                const attendancePromises = branches.map(b => storageService.getAttendanceByDate(todayStr, b.id));

                const [classResults, attendanceResults] = await Promise.all([
                    Promise.all(classPromises),
                    Promise.all(attendancePromises)
                ]);
                
                // Process Classes
                let allMyClasses = [];
                classResults.forEach((data, idx) => {
                    const branchName = branches[idx].name;
                    const branchId = branches[idx].id;
                    const branchClasses = (data || []).map(c => ({ ...c, branchName, branchId }));
                    allMyClasses = [...allMyClasses, ...branchClasses];
                });
                setInstructorClasses(allMyClasses);

                // Process Attendance Baseline
                let allBaselineAttendance = [];
                attendanceResults.forEach((data, idx) => {
                    const branchName = branches[idx].name;
                    const branchId = branches[idx].id;
                    
                    const myBranchClasses = allMyClasses.filter(c => c.branchId === branchId);
                    const myClassTitles = new Set(myBranchClasses.map(c => c.title));

                    console.log(`[InstructorPage] Branch: ${branchId}, Fetched: ${data?.length} logs`);
                    
                    const branchRecords = (data || [])
                        .filter(r => {
                            // Relaxed Filtering Logic
                            const recordInstructor = r.instructor ? r.instructor.trim() : '';
                            const currentInstructor = instructorName.trim();
                            
                            const isExactMatch = recordInstructor === currentInstructor;
                            const isUndesignated = recordInstructor === '誘몄??? || !recordInstructor;
                            const isClassMatch = myClassTitles.has(r.className);

                            // Debug logging for unmatched but potential candidates
                            if (isUndesignated && isClassMatch) {
                                console.log('[InstructorPage] Included Undesignated:', r);
                            }

                            return isExactMatch || (isUndesignated && isClassMatch);
                        })
                        .map(r => ({ ...r, branchName, branchId }));
                    allBaselineAttendance = [...allBaselineAttendance, ...branchRecords];
                });
                
                allBaselineAttendance.forEach(a => a._ts = new Date(a.timestamp).getTime());
                setAttendance(allBaselineAttendance.sort((a, b) => b._ts - a._ts));
                setAttendanceLoading(false); // Initial load done

                // 2. Real-time Subscription (Moved inside to access allMyClasses)
                const newUnsubscribes = branches.map(branch => {
                    return storageService.subscribeAttendance(todayStr, branch.id, (records) => {
                        setAttendance(prev => {
                            const otherBranches = prev.filter(r => r.branchId !== branch.id);
                            const branchName = branch.name;
                            const branchId = branch.id;
                            
                            // Re-filter with the known classes
                            const myBranchClasses = allMyClasses.filter(c => c.branchId === branchId);
                            const myClassTitles = new Set(myBranchClasses.map(c => c.title));

                            const branchRecords = (records || [])
                                .filter(r => {
                                    const recordInstructor = r.instructor ? r.instructor.trim() : '';
                                    const currentInstructor = instructorName.trim();
                                    
                                    const isExactMatch = recordInstructor === currentInstructor;
                                    const isUndesignated = recordInstructor === '誘몄??? || !recordInstructor;
                                    const isClassMatch = myClassTitles.has(r.className);
                                    
                                    return isExactMatch || (isUndesignated && isClassMatch);
                                })
                                .map(r => ({ ...r, branchName, branchId }));
                            
                            const merged = [...otherBranches, ...branchRecords];
                            merged.sort((a, b) => {
                                const ta = a._ts || (a._ts = new Date(a.timestamp).getTime());
                                const tb = b._ts || (b._ts = new Date(b.timestamp).getTime());
                                return tb - ta;
                            });
                            return merged;
                        });
                    });
                });
                unsubscribesRef.current = newUnsubscribes;

            } catch (e) {
                console.error('Failed to load initial data:', e);
                setAttendanceLoading(false);
            }
        };

        loadInitialData();

        // Cleanup function
        return () => {
             if (unsubscribesRef.current) {
                unsubscribesRef.current.forEach(unsub => unsub());
             }
        };
    }, [instructorName, todayStr, branches]);

    // Initialize AI Greeting (Instant + Background Fetch)
    // [FIX] ?섏〈?깆뿉??attendance.length ?쒓굅 ??源쒕묀??諛⑹?
    useEffect(() => {
        if (!instructorName) return;

        const dayOfWeek = ['??, '??, '??, '??, '紐?, '湲?, '??][getKSTDayOfWeek()];
        
        // 1. Try Cache First for instant display
        const cacheKey = `ai_greeting_${instructorName}_${todayStr}_${hour}`;
        const cached = localStorage.getItem(cacheKey);
        
        if (cached) {
            setAiGreeting(cached);
            // 罹먯떆媛 ?덉쑝硫?AI ?ы샇異쒗븯吏 ?딆쓬 ??源쒕묀???꾩쟾 諛⑹?
            return;
        }
        
        // If no cache, set default instant message
