                    <div style={{ margin: '4px 0 0', fontSize: '0.9rem', color: 'var(--text-secondary)' }}>{instructorName} ?좎깮??/div>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
