            <div style={{
                position: 'fixed', bottom: 0, left: 0, right: 0, background: 'var(--bg-surface)',
                display: 'flex', justifyContent: 'space-around', padding: '8px 0', borderTop: '1px solid var(--border-color)',
                zIndex: 10
            }}>
                <TabButton icon={<House size={24} />} label="??

怨듭?" active={activeTab === 'notices'} onClick={() => setActiveTab('notices')} />
            </div>

            <InstallBanner onManualInstallClick={() => setShowInstallGuide(true)} />
            <InstallGuideModal isOpen={showInstallGuide} onClose={() => setShowInstallGuide(false)} />
            <div style={{ textAlign: 'center', padding: '16px 0 80px', position: 'relative', zIndex: 1 }}>
                <a href="/privacy" target="_blank" rel="noopener noreferrer" style={{ fontSize: '0.7rem', color: 'rgba(255,255,255,0.2)', textDecoration: 'none' }}>媛쒖씤?뺣낫泥섎━諛⑹묠</a>
            </div>
        </div>
    );
};

const TabButton = ({ icon, label, active, onClick }) => (
    <button
        onClick={onClick}
        style={{
            background: 'none', 
            border: 'none', 
            display: 'flex', 
            flexDirection: 'column', 
            alignItems: 'center', 
            gap: '4px',
            color: active ? 'var(--primary-gold)' : 'var(--text-secondary)', 
            cursor: 'pointer',
            padding: '12px 20px',
            minWidth: '64px',
            touchAction: 'manipulation',
            userSelect: 'none',
            WebkitTapHighlightColor: 'transparent',
            transition: 'transform 0.1s, opacity 0.1s'
        }}
    >
        {icon}
        <span style={{ fontSize: '0.75rem' }}>{label}</span>
    </button>
);

const navBtnStyle = {
    background: 'var(--bg-input)', border: 'none', color: 'var(--text-primary)', width: '36px', height: '36px',
    borderRadius: '50%', cursor: 'pointer', fontSize: '1rem'
};

export default InstructorPage;

